{
  "name": "Heavy Vehicle Maintenance - Fire Extinguishers",
  "description": "A rugged, industrial-style maintenance app for field technicians to report fire extinguisher status in high-pressure environments.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum FlowStep {
  TRIGGER = 'TRIGGER',
  IDENTIFY = 'IDENTIFY',
  DATA_ENTRY = 'DATA_ENTRY',
  SUCCESS = 'SUCCESS'
}

export enum ActionType {
  DISASSEMBLE = 'DISASSEMBLE',
  ASSEMBLE = 'ASSEMBLE'
}

export interface Extinguisher {
  id: string;
  name: string;
  serialNumber: string;
}

import React, { useState, useCallback, useEffect } from 'react';
import { FlowStep, ActionType, Extinguisher } from './types';
import TriggerScreen from './components/TriggerScreen';
import IdentifyScreen from './components/IdentifyScreen';
import DataEntryScreen from './components/DataEntryScreen';
import SuccessScreen from './components/SuccessScreen';

const MOCK_EXTINGUISHERS: Extinguisher[] = [
  { id: '1', name: 'מטף נהג', serialNumber: 'צד"י 12345' },
  { id: '2', name: 'מטף תא לוחמים', serialNumber: 'צד"י 67890' },
  { id: '3', name: 'מטף צריח חיצוני', serialNumber: 'צד"י 11223' },
];

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<FlowStep>(FlowStep.TRIGGER);
  const [action, setAction] = useState<ActionType | null>(null);
  const [selectedExtinguisher, setSelectedExtinguisher] = useState<Extinguisher | null>(null);
  const [counterValue, setCounterValue] = useState<string>('');

  const handleActionSelect = (type: ActionType) => {
    setAction(type);
    setCurrentStep(FlowStep.IDENTIFY);
  };

  const handleExtinguisherSelect = (ext: Extinguisher) => {
    setSelectedExtinguisher(ext);
    setCurrentStep(FlowStep.DATA_ENTRY);
  };

  const handleDataSubmit = (value: string) => {
    setCounterValue(value);
    setCurrentStep(FlowStep.SUCCESS);
  };

  const handleReset = () => {
    setAction(null);
    setSelectedExtinguisher(null);
    setCounterValue('');
    setCurrentStep(FlowStep.TRIGGER);
  };

  const renderStep = () => {
    switch (currentStep) {
      case FlowStep.TRIGGER:
        return <TriggerScreen onSelect={handleActionSelect} />;
      case FlowStep.IDENTIFY:
        return (
          <IdentifyScreen 
            extinguishers={MOCK_EXTINGUISHERS} 
            onSelect={handleExtinguisherSelect}
            onBack={() => setCurrentStep(FlowStep.TRIGGER)}
          />
        );
      case FlowStep.DATA_ENTRY:
        return (
          <DataEntryScreen 
            onConfirm={handleDataSubmit}
            onBack={() => setCurrentStep(FlowStep.IDENTIFY)}
            extinguisherName={selectedExtinguisher?.name || ''}
          />
        );
      case FlowStep.SUCCESS:
        return (
          <SuccessScreen 
            extinguisherName={selectedExtinguisher?.name || ''}
            serialNumber={selectedExtinguisher?.serialNumber || ''}
            onFinish={handleReset} 
          />
        );
      default:
        return <TriggerScreen onSelect={handleActionSelect} />;
    }
  };

  return (
    <div className="h-screen w-full flex flex-col bg-[#0F172A] selection:bg-orange-500/30">
      {/* Header Bar - Static for context */}
      <header className="px-6 py-4 flex justify-between items-center border-b border-slate-800 bg-[#1E293B]">
        <div className="flex flex-col">
          <h1 className="text-xs uppercase tracking-widest text-slate-400 font-bold">ניהול אמצעי כיבוי</h1>
          <p className="text-lg font-extrabold text-white">נגמ"ש איתן - 123456</p>
        </div>
        <div className="w-10 h-10 rounded-full bg-slate-700 flex items-center justify-center">
          <span className="text-sm font-bold">א"ב</span>
        </div>
      </header>

      {/* Dynamic Content */}
      <main className="flex-1 overflow-y-auto relative p-6">
        {renderStep()}
      </main>

      {/* Progress Indicator (Subtle) */}
      <div className="px-6 pb-4 flex gap-2">
        {Object.values(FlowStep).map((step, idx) => (
          <div 
            key={step} 
            className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
              Object.values(FlowStep).indexOf(currentStep) >= idx 
                ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.5)]' 
                : 'bg-slate-800'
            }`} 
          />
        ))}
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { ActionType } from '../types';

