    <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-4 duration-500">
      <div className="mb-6 flex items-start justify-between">
        <div>
          <h2 className="text-4xl font-black text-white">איזה מטף פירקת?</h2>
