      <div className="mt-8">
        <button className="w-full flex items-center justify-center gap-3 p-6 bg-slate-700/50 border-2 border-dashed border-slate-600 rounded-3xl text-slate-300 active:bg-slate-600 transition-all font-bold text-xl">
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
          </svg>
          המטף לא מופיע? סרוק ברקוד
        </button>
      </div>
    </div>
  );
};

export default IdentifyScreen;

import React, { useState } from 'react';

interface DataEntryScreenProps {
  onConfirm: (value: string) => void;
  onBack: () => void;
  extinguisherName: string;
}

const DataEntryScreen: React.FC<DataEntryScreenProps> = ({ onConfirm, onBack, extinguisherName }) => {
  const [value, setValue] = useState('');

  // Logical validation check (Simplified for UI demo)
  const isValid = value.length >= 3 && parseInt(value) > 100;

  const handleKeyPress = (num: string) => {
    if (value.length < 8) setValue(prev => prev + num);
  };

  const handleDelete = () => {
    setValue(prev => prev.slice(0, -1));
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in zoom-in-95 duration-500">
      <div className="mb-4 flex items-start justify-between">
        <div>
          <h2 className="text-4xl font-black text-white">דיווח שע"מ</h2>
          <p className="text-slate-400 text-lg mt-1 font-bold">הזן מונה נוכחי עבור <span className="text-orange-400">{extinguisherName}</span></p>
        </div>
        <button onClick={onBack} className="p-4 bg-slate-800 rounded-2xl active:bg-slate-700">
          <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      <div className="bg-slate-800 rounded-3xl p-8 mb-6 border-2 border-slate-700 flex flex-col items-center">
        <div className="flex items-center justify-center gap-4 w-full">
          <div className={`text-6xl font-black tracking-widest ${value ? 'text-white' : 'text-slate-600'}`}>
            {value || '00000'}
          </div>
          {isValid && (
            <div className="bg-emerald-500 rounded-full p-1 animate-in zoom-in duration-300">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
              </svg>
            </div>
          )}
        </div>
        <div className="mt-2 text-slate-400 font-bold">שעות מנוע (שע"מ)</div>
      </div>

      {/* Industrial Custom Numpad */}
      <div className="flex-1 grid grid-cols-3 gap-2 pb-4">
        {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
          <button 
            key={num} 
            onClick={() => handleKeyPress(num.toString())}
            className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-600 border-b-4 border-slate-900"
          >
            {num}
          </button>
        ))}
        <button className="bg-slate-800/40 rounded-2xl"></button>
        <button 
          onClick={() => handleKeyPress('0')}
          className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-600 border-b-4 border-slate-900"
        >
          0
        </button>
        <button 
          onClick={handleDelete}
          className="bg-red-900/40 rounded-2xl text-3xl font-bold text-red-400 active:bg-red-800 border-b-4 border-slate-900 flex items-center justify-center"
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2M3 12l6.414 6.414a2 2 0 001.414.586H19a2 2 0 002-2V7a2 2 0 00-2-2h-8.172a2 2 0 00-1.414.586L3 12z" />
          </svg>
        </button>
      </div>

      <button
        disabled={!isValid}
        onClick={() => onConfirm(value)}
        className={`w-full py-8 rounded-3xl text-3xl font-black transition-all shadow-xl active:scale-95 ${
          isValid ? 'bg-orange-500 text-white shadow-orange-500/20' : 'bg-slate-800 text-slate-600 grayscale cursor-not-allowed'
        }`}
      >
        אישור וסיום דיווח
      </button>
    </div>
  );
};

export default DataEntryScreen;

import React, { useEffect } from 'react';

interface SuccessScreenProps {
  extinguisherName: string;
  serialNumber: string;
  onFinish: () => void;
}

const SuccessScreen: React.FC<SuccessScreenProps> = ({ extinguisherName, serialNumber, onFinish }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onFinish();
    }, 5000);
    return () => clearTimeout(timer);
  }, [onFinish]);

  return (
    <div className="h-full flex flex-col items-center justify-center text-center animate-in fade-in zoom-in duration-700">
      <div className="w-40 h-40 bg-emerald-500 rounded-full flex items-center justify-center mb-8 shadow-[0_0_50px_rgba(16,185,129,0.3)] animate-bounce-short">
        <svg className="w-24 h-24 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
        </svg>
      </div>

      <h2 className="text-5xl font-black text-white mb-4">הדיווח נקלט בהצלחה!</h2>

      <div className="bg-slate-800/50 border border-slate-700 rounded-3xl p-6 max-w-sm mb-12">
        <p className="text-xl text-slate-300 leading-relaxed font-bold">
          <span className="text-orange-400">{extinguisherName}</span> ({serialNumber}) <br/>
          הועבר לסטטוס <span className="text-orange-500 underline underline-offset-4">"בתיקון"</span>. <br/>
          המלאי ב-SAP עודכן.
        </p>
      </div>

      <button
        onClick={onFinish}
        className="w-full py-6 bg-slate-100 text-slate-900 rounded-3xl text-2xl font-black active:bg-white shadow-xl"
      >
        חזור למסך הראשי
      </button>

      <p className="mt-6 text-slate-500 font-bold animate-pulse">
        המסך ייסגר אוטומטית בעוד 5 שניות...
      </p>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes bounce-short {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        .animate-bounce-short {
          animation: bounce-short 2s infinite ease-in-out;
        }
      `}} />
    </div>
  );
};

export default SuccessScreen;

export enum FlowStep {
  TRIGGER = 'TRIGGER',
  IDENTIFY = 'IDENTIFY',
  DATA_ENTRY = 'DATA_ENTRY',
  SUCCESS = 'SUCCESS',
  AUDIT_CHECK = 'AUDIT_CHECK',
  AUDIT_SUMMARY = 'AUDIT_SUMMARY',
  NEXT_VEHICLE = 'NEXT_VE_INPUT',
  BATCH_SUMMARY = 'BATCH_SUMMARY'
}

export enum ActionType {
  DISASSEMBLE = 'DISASSEMBLE',
  ASSEMBLE = 'ASSEMBLE',
  AUDIT = 'AUDIT'
}

export interface Extinguisher {
  id: string;
  name: string;
  serialNumber: string;
  status?: 'ok' | 'anomaly' | null;
}

export interface BatchStats {
  vehiclesCount: number;
  extinguishersChecked: number;
  anomaliesFound: number;
}

import React, { useState } from 'react';
import { FlowStep, ActionType, Extinguisher, BatchStats } from './types';
import TriggerScreen from './components/TriggerScreen';
import IdentifyScreen from './components/IdentifyScreen';
import DataEntryScreen from './components/DataEntryScreen';
import SuccessScreen from './components/SuccessScreen';
import AuditScreen from './components/AuditScreen';
import AuditSummaryScreen from './components/AuditSummaryScreen';
import NextVehicleScreen from './components/NextVehicleScreen';
import BatchSummaryScreen from './components/BatchSummaryScreen';

const MOCK_EXTINGUISHERS: Extinguisher[] = [
  { id: '1', name: 'מטף נהג', serialNumber: 'צד"י 12345', status: null },
  { id: '2', name: 'מטף תא לוחמים', serialNumber: 'צד"י 67890', status: null },
  { id: '3', name: 'מטף צריח חיצוני', serialNumber: 'צד"י 11223', status: null },
];

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<FlowStep>(FlowStep.TRIGGER);
  const [action, setAction] = useState<ActionType | null>(null);
  const [selectedExtinguisher, setSelectedExtinguisher] = useState<Extinguisher | null>(null);
  const [currentVehicleId, setCurrentVehicleId] = useState('123456');

  // Audit related state
  const [auditList, setAuditList] = useState<Extinguisher[]>(MOCK_EXTINGUISHERS);
  const [batchStats, setBatchStats] = useState<BatchStats>({
    vehiclesCount: 0,
    extinguishersChecked: 0,
    anomaliesFound: 0
  });

  const handleActionSelect = (type: ActionType) => {
    setAction(type);
    if (type === ActionType.AUDIT) {
      setAuditList(MOCK_EXTINGUISHERS.map(e => ({ ...e, status: null })));
      setCurrentStep(FlowStep.AUDIT_CHECK);
    } else {
      setCurrentStep(FlowStep.IDENTIFY);
    }
  };

  const handleExtinguisherSelect = (ext: Extinguisher) => {
    setSelectedExtinguisher(ext);
    setCurrentStep(FlowStep.DATA_ENTRY);
  };

  const handleAuditFinish = () => {
    setCurrentStep(FlowStep.AUDIT_SUMMARY);
  };

  const handleAuditFinalSubmit = (mileage: string) => {
    // Update batch stats
    const anomalies = auditList.filter(e => e.status === 'anomaly').length;
    setBatchStats(prev => ({
      vehiclesCount: prev.vehiclesCount + 1,
      extinguishersChecked: prev.extinguishersChecked + auditList.length,
      anomaliesFound: prev.anomaliesFound + anomalies
    }));
    setCurrentStep(FlowStep.NEXT_VE_INPUT);
  };

  const handleNewVehicle = (newId: string) => {
    setCurrentVehicleId(newId);
    setAuditList(MOCK_EXTINGUISHERS.map(e => ({ ...e, status: null })));
    setCurrentStep(FlowStep.AUDIT_CHECK);
  };

  const handleReset = () => {
    setAction(null);
    setSelectedExtinguisher(null);
    setCurrentStep(FlowStep.TRIGGER);
  };

  const renderStep = () => {
    switch (currentStep) {
      case FlowStep.TRIGGER:
        return <TriggerScreen onSelect={handleActionSelect} />;
      case FlowStep.IDENTIFY:
        return (
          <IdentifyScreen 
            extinguishers={MOCK_EXTINGUISHERS} 
            onSelect={handleExtinguisherSelect}
            onBack={handleReset}
          />
        );
      case FlowStep.DATA_ENTRY:
        return (
          <DataEntryScreen 
            onConfirm={() => setCurrentStep(FlowStep.SUCCESS)}
            onBack={() => setCurrentStep(FlowStep.IDENTIFY)}
            extinguisherName={selectedExtinguisher?.name || ''}
          />
        );
      case FlowStep.AUDIT_CHECK:
        return (
          <AuditScreen 
            items={auditList} 
            setItems={setAuditList} 
            onFinish={handleAuditFinish} 
            onBack={handleReset}
            vehicleId={currentVehicleId}
          />
        );
      case FlowStep.AUDIT_SUMMARY:
        return (
          <AuditSummaryScreen 
            items={auditList} 
            onConfirm={handleAuditFinalSubmit}
            onBack={() => setCurrentStep(FlowStep.AUDIT_CHECK)}
          />
        );
      case FlowStep.NEXT_VE_INPUT:
        return (
          <NextVehicleScreen 
            onNext={handleNewVehicle} 
            onFinishBatch={() => setCurrentStep(FlowStep.BATCH_SUMMARY)} 
          />
        );
      case FlowStep.BATCH_SUMMARY:
        return <BatchSummaryScreen stats={batchStats} onFinish={handleReset} />;
      case FlowStep.SUCCESS:
        return (
          <SuccessScreen 
            extinguisherName={selectedExtinguisher?.name || ''}
            serialNumber={selectedExtinguisher?.serialNumber || ''}
            onFinish={handleReset} 
          />
        );
      default:
        return <TriggerScreen onSelect={handleActionSelect} />;
    }
  };

  return (
    <div className="h-screen w-full flex flex-col bg-[#0F172A] text-slate-100 overflow-hidden font-['Assistant']">
      <header className="px-6 py-4 flex justify-between items-center border-b border-slate-800 bg-[#1E293B]">
        <div className="flex flex-col">
          <h1 className="text-xs uppercase tracking-widest text-slate-400 font-bold">ניהול אמצעי כיבוי</h1>
          <p className="text-lg font-extrabold text-white">כלי: {currentVehicleId}</p>
        </div>
        <div className="flex items-center gap-3">
           <div className="hidden md:block text-left">
              <p className="text-xs text-slate-400 font-bold">טכנאי מורשה</p>
              <p className="text-sm font-bold">אלכס ב.</p>
           </div>
           <div className="w-10 h-10 rounded-full bg-orange-500/20 border border-orange-500 flex items-center justify-center">
             <span className="text-sm font-extrabold text-orange-500">א"ב</span>
           </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto relative p-6">
        {renderStep()}
      </main>

      <div className="px-6 pb-6 flex gap-2">
        {Object.values(FlowStep).slice(0, 4).map((step, idx) => {
          const isActive = currentStep === step || 
            (currentStep.startsWith('AUDIT') && idx === 1) || 
            (currentStep === FlowStep.NEXT_VE_INPUT && idx === 2);
          return (
            <div 
              key={step} 
              className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
