import React, { useState } from 'react';
import { FlowStep, ActionType, Extinguisher, BatchStats } from './types';
import TriggerScreen from './components/TriggerScreen';
import IdentifyScreen from './components/IdentifyScreen';
import DataEntryScreen from './components/DataEntryScreen';
import SuccessScreen from './components/SuccessScreen';
import AuditScreen from './components/AuditScreen';
import AuditSummaryScreen from './components/AuditSummaryScreen';
import NextVehicleScreen from './components/NextVehicleScreen';
import BatchSummaryScreen from './components/BatchSummaryScreen';

const MOCK_EXTINGUISHERS: Extinguisher[] = [
  { id: '1', name: 'מטף נהג', serialNumber: 'צד"י 12345', status: null },
  { id: '2', name: 'מטף תא לוחמים', serialNumber: 'צד"י 67890', status: null },
  { id: '3', name: 'מטף צריח חיצוני', serialNumber: 'צד"י 11223', status: null },
];

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<FlowStep>(FlowStep.TRIGGER);
  const [action, setAction] = useState<ActionType | null>(null);
  const [selectedExtinguisher, setSelectedExtinguisher] = useState<Extinguisher | null>(null);
  const [currentVehicleId, setCurrentVehicleId] = useState('123456');

  // Audit related state
  const [auditList, setAuditList] = useState<Extinguisher[]>(MOCK_EXTINGUISHERS);
  const [batchStats, setBatchStats] = useState<BatchStats>({
    vehiclesCount: 0,
    extinguishersChecked: 0,
    anomaliesFound: 0
  });

  const handleActionSelect = (type: ActionType) => {
    setAction(type);
    if (type === ActionType.AUDIT) {
      setAuditList(MOCK_EXTINGUISHERS.map(e => ({ ...e, status: null })));
      setCurrentStep(FlowStep.AUDIT_CHECK);
    } else {
      setCurrentStep(FlowStep.IDENTIFY);
    }
  };

  const handleExtinguisherSelect = (ext: Extinguisher) => {
    setSelectedExtinguisher(ext);
    setCurrentStep(FlowStep.DATA_ENTRY);
  };

  const handleAuditFinish = () => {
    setCurrentStep(FlowStep.AUDIT_SUMMARY);
  };

  const handleAuditFinalSubmit = (mileage: string) => {
    // Update batch stats
    const anomalies = auditList.filter(e => e.status === 'anomaly').length;
    setBatchStats(prev => ({
      vehiclesCount: prev.vehiclesCount + 1,
      extinguishersChecked: prev.extinguishersChecked + auditList.length,
      anomaliesFound: prev.anomaliesFound + anomalies
    }));
    // Fix: Updated reference to FlowStep.NEXT_VEHICLE
    setCurrentStep(FlowStep.NEXT_VEHICLE);
  };

  const handleNewVehicle = (newId: string) => {
    setCurrentVehicleId(newId);
    setAuditList(MOCK_EXTINGUISHERS.map(e => ({ ...e, status: null })));
    setCurrentStep(FlowStep.AUDIT_CHECK);
  };

  const handleReset = () => {
    setAction(null);
    setSelectedExtinguisher(null);
    setCurrentStep(FlowStep.TRIGGER);
  };

  const renderStep = () => {
    switch (currentStep) {
      case FlowStep.TRIGGER:
        return <TriggerScreen onSelect={handleActionSelect} />;
      case FlowStep.IDENTIFY:
        return (
          <IdentifyScreen 
            extinguishers={MOCK_EXTINGUISHERS} 
            onSelect={handleExtinguisherSelect}
            onBack={handleReset}
          />
        );
      case FlowStep.DATA_ENTRY:
        return (
          <DataEntryScreen 
            onConfirm={() => setCurrentStep(FlowStep.SUCCESS)}
            onBack={() => setCurrentStep(FlowStep.IDENTIFY)}
            extinguisherName={selectedExtinguisher?.name || ''}
          />
        );
      case FlowStep.AUDIT_CHECK:
        return (
          <AuditScreen 
            items={auditList} 
            setItems={setAuditList} 
            onFinish={handleAuditFinish} 
            onBack={handleReset}
            vehicleId={currentVehicleId}
          />
        );
      case FlowStep.AUDIT_SUMMARY:
        return (
          <AuditSummaryScreen 
            items={auditList} 
            onConfirm={handleAuditFinalSubmit}
            onBack={() => setCurrentStep(FlowStep.AUDIT_CHECK)}
          />
        );
      // Fix: Updated reference to FlowStep.NEXT_VEHICLE
      case FlowStep.NEXT_VEHICLE:
        return (
          <NextVehicleScreen 
            onNext={handleNewVehicle} 
            onFinishBatch={() => setCurrentStep(FlowStep.BATCH_SUMMARY)} 
          />
        );
      case FlowStep.BATCH_SUMMARY:
        return <BatchSummaryScreen stats={batchStats} onFinish={handleReset} />;
      case FlowStep.SUCCESS:
        return (
          <SuccessScreen 
            extinguisherName={selectedExtinguisher?.name || ''}
            serialNumber={selectedExtinguisher?.serialNumber || ''}
            onFinish={handleReset} 
          />
        );
      default:
        return <TriggerScreen onSelect={handleActionSelect} />;
    }
  };

  return (
    <div className="h-screen w-full flex flex-col bg-[#0F172A] text-slate-100 overflow-hidden font-['Assistant']">
      <header className="px-6 py-4 flex justify-between items-center border-b border-slate-800 bg-[#1E293B]">
        <div className="flex flex-col">
          <h1 className="text-xs uppercase tracking-widest text-slate-400 font-bold">ניהול אמצעי כיבוי</h1>
          <p className="text-lg font-extrabold text-white">כלי: {currentVehicleId}</p>
        </div>
        <div className="flex items-center gap-3">
           <div className="hidden md:block text-left">
              <p className="text-xs text-slate-400 font-bold">טכנאי מורשה</p>
              <p className="text-sm font-bold">אלכס ב.</p>
           </div>
           <div className="w-10 h-10 rounded-full bg-orange-500/20 border border-orange-500 flex items-center justify-center">
             <span className="text-sm font-extrabold text-orange-500">א"ב</span>
           </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto relative p-6">
        {renderStep()}
      </main>

      <div className="px-6 pb-6 flex gap-2">
        {Object.values(FlowStep).slice(0, 4).map((step, idx) => {
          const isActive = currentStep === step || 
            (currentStep.startsWith('AUDIT') && idx === 1) || 
            // Fix: Updated reference to FlowStep.NEXT_VEHICLE
            (currentStep === FlowStep.NEXT_VEHICLE && idx === 2);
          return (
            <div 
              key={step} 
              className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
                isActive ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.5)]' : 'bg-slate-800'
              }`} 
            />
          );
        })}
      </div>
    </div>
  );
};

export default App;

export enum FlowStep {
  TRIGGER = 'TRIGGER',
  IDENTIFY = 'IDENTIFY',
  DATA_ENTRY = 'DATA_ENTRY',
  SUCCESS = 'SUCCESS',
  AUDIT_CHECK = 'AUDIT_CHECK',
  AUDIT_SUMMARY = 'AUDIT_SUMMARY',
  NEXT_VEHICLE = 'NEXT_VE_INPUT',
  BATCH_SUMMARY = 'BATCH_SUMMARY'
}

export enum ActionType {
  DISASSEMBLE = 'DISASSEMBLE',
  ASSEMBLE = 'ASSEMBLE',
  AUDIT = 'AUDIT'
}

export interface Extinguisher {
  id: string;
  name: string;
  serialNumber: string;
  status?: 'ok' | 'anomaly' | null;
  actualSerialNumber?: string; // For audit discrepancies
  counters?: string[]; // Multiple counters support
}

export interface BatchStats {
  vehiclesCount: number;
  extinguishersChecked: number;
  anomaliesFound: number;
}

