import React, { useState } from 'react';

interface DataEntryScreenProps {
  onConfirm: (counters: string[]) => void;
  onBack: () => void;
  extinguisherName: string;
}

const DataEntryScreen: React.FC<DataEntryScreenProps> = ({ onConfirm, onBack, extinguisherName }) => {
  const [counters, setCounters] = useState<string[]>([]);
  const [currentValue, setCurrentValue] = useState('');

  const isValidEntry = currentValue.length >= 3;

  const handleKeyPress = (num: string) => {
    if (currentValue.length < 8) setCurrentValue(prev => prev + num);
  };

  const handleDelete = () => {
    setCurrentValue(prev => prev.slice(0, -1));
  };

  const addCounter = () => {
    if (isValidEntry) {
      setCounters(prev => [...prev, currentValue]);
      setCurrentValue('');
    }
  };

  const removeCounter = (index: number) => {
    setCounters(prev => prev.filter((_, i) => i !== index));
  };

  const canFinish = counters.length > 0 || isValidEntry;

  const handleFinalConfirm = () => {
    let finalCounters = [...counters];
    if (currentValue) finalCounters.push(currentValue);
    onConfirm(finalCounters);
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in zoom-in-95 duration-500">
      <div className="mb-4 flex items-start justify-between">
        <div>
          <h2 className="text-4xl font-black text-white">דיווח מונים</h2>
          <p className="text-slate-400 text-lg mt-1 font-bold italic">
            הזן שע"מ/ק"מ עבור <span className="text-orange-400">{extinguisherName}</span>
          </p>
        </div>
        <button onClick={onBack} className="p-4 bg-slate-800 rounded-2xl active:bg-slate-700">
          <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Counters List */}
      <div className="flex flex-wrap gap-2 mb-4">
        {counters.map((c, i) => (
          <div key={i} className="bg-orange-500/20 border border-orange-500/50 rounded-xl px-4 py-2 flex items-center gap-3 animate-in zoom-in">
            <span className="font-bold text-orange-500">{c}</span>
            <button onClick={() => removeCounter(i)} className="text-orange-300/50 hover:text-orange-300">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        ))}
        {counters.length === 0 && !currentValue && <p className="text-slate-500 italic">טרם הוזנו מונים...</p>}
      </div>

      <div className="bg-slate-800 rounded-3xl p-6 mb-4 border-2 border-slate-700 flex flex-col items-center">
        <div className="flex items-center justify-center gap-4 w-full">
          <div className={`text-6xl font-black tracking-widest ${currentValue ? 'text-white' : 'text-slate-600'}`}>
            {currentValue || '00000'}
          </div>
          <button 
            onClick={addCounter}
            disabled={!isValidEntry}
            className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${isValidEntry ? 'bg-emerald-500 text-white active:scale-90' : 'bg-slate-700 text-slate-500'}`}
          >
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M12 4v16m8-8H4" />
            </svg>
          </button>
        </div>
      </div>

      {/* Industrial Custom Numpad */}
      <div className="flex-1 grid grid-cols-3 gap-2 pb-4">
        {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
          <button 
            key={num} 
            onClick={() => handleKeyPress(num.toString())}
            className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-600 border-b-4 border-slate-900"
          >
            {num}
          </button>
        ))}
        <button className="bg-slate-800/40 rounded-2xl"></button>
        <button 
          onClick={() => handleKeyPress('0')}
          className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-600 border-b-4 border-slate-900"
        >
          0
        </button>
        <button 
          onClick={handleDelete}
          className="bg-red-900/40 rounded-2xl text-3xl font-bold text-red-400 active:bg-red-800 border-b-4 border-slate-900 flex items-center justify-center"
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2M3 12l6.414 6.414a2 2 0 001.414.586H19a2 2 0 002-2V7a2 2 0 00-2-2h-8.172a2 2 0 00-1.414.586L3 12z" />
          </svg>
        </button>
      </div>

      <button
        disabled={!canFinish}
        onClick={handleFinalConfirm}
        className={`w-full py-8 rounded-3xl text-3xl font-black transition-all shadow-xl active:scale-95 ${
          canFinish ? 'bg-orange-500 text-white shadow-orange-500/20' : 'bg-slate-800 text-slate-600 grayscale cursor-not-allowed'
        }`}
      >
        אישור וסיום דיווח
      </button>
    </div>
  );
};

