                <label className="block text-slate-400 text-sm font-bold mb-2 mr-1">הזן מספר צד״י של המטף שנמצא בפועל:</label>
                <input 
                  type="text"
                  placeholder="מספר צד״י נוכחי..."
                  value={item.actualSerialNumber || ''}
                  onChange={(e) => updateActualId(item.id, e.target.value)}
                  className="w-full bg-slate-900 border-2 border-slate-600 rounded-2xl p-4 text-xl font-bold text-white outline-none focus:border-red-500 transition-all"
                />
              </div>
