        ))}
      </div>

      <button
        disabled={!allChecked}
        onClick={onFinish}
        className={`mt-6 w-full py-6 rounded-3xl text-2xl font-black transition-all shadow-xl ${
          allChecked ? 'bg-orange-500 text-white shadow-orange-500/20' : 'bg-slate-800 text-slate-600 grayscale cursor-not-allowed'
        }`}
      >
        סיום אימות
      </button>
    </div>
  );
};

