import React, { useState, useEffect } from 'react';
import { Extinguisher, CounterType, CounterValue } from '../types';

interface DataEntryScreenProps {
  onConfirm: (counters: CounterValue[]) => void;
  onBack: () => void;
  extinguisher: Extinguisher | null;
}

const COUNTER_TYPES: CounterType[] = ['שע"מ', 'ק"מ', 'מייל'];

const DataEntryScreen: React.FC<DataEntryScreenProps> = ({ onConfirm, onBack, extinguisher }) => {
  const [completedCounters, setCompletedCounters] = useState<CounterValue[]>([]);
  const [currentValue, setCurrentValue] = useState('');
  const [selectedType, setSelectedType] = useState<CounterType>('שע"מ');

  // Determine current requirement
  const requiredTypes = extinguisher?.requiredCounters || [];
  const isDynamic = extinguisher?.isNew || requiredTypes.length === 0;

  // Find next required type that hasn't been filled
  useEffect(() => {
    if (!isDynamic) {
      const next = requiredTypes.find(type => !completedCounters.find(c => c.type === type));
      if (next) setSelectedType(next);
    }
  }, [completedCounters, requiredTypes, isDynamic]);

  const isValidEntry = currentValue.length >= 2;

  const handleKeyPress = (num: string) => {
    if (currentValue.length < 8) setCurrentValue(prev => prev + num);
  };

  const handleDelete = () => {
    setCurrentValue(prev => prev.slice(0, -1));
  };

  const addCounter = () => {
    if (isValidEntry) {
      setCompletedCounters(prev => [...prev, { type: selectedType, value: currentValue }]);
      setCurrentValue('');
      // If dynamic, user keeps control. If static, useEffect handles next type.
    }
  };

  const removeCounter = (index: number) => {
    setCompletedCounters(prev => prev.filter((_, i) => i !== index));
  };

  // Logic for finishing
  const allRequiredMet = isDynamic 
    ? (completedCounters.length > 0 || isValidEntry)
    : requiredTypes.every(type => completedCounters.find(c => c.type === type) || (selectedType === type && isValidEntry));

  const handleFinalConfirm = () => {
    let final = [...completedCounters];
    if (currentValue && isValidEntry) {
      // Check if we already have this type or if it's needed
      if (!final.find(c => c.type === selectedType)) {
        final.push({ type: selectedType, value: currentValue });
      }
    }
    onConfirm(final);
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in zoom-in-95 duration-500">
      <div className="mb-4 flex items-start justify-between">
        <div>
          <h2 className="text-4xl font-black text-white">דיווח מונים</h2>
          <p className="text-slate-400 text-lg mt-1 font-bold italic leading-tight">
            הזן נתונים עבור <span className="text-orange-400">{extinguisher?.name}</span>
          </p>
        </div>
        <button onClick={onBack} className="p-4 bg-slate-800 rounded-2xl active:bg-slate-700">
          <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Required Info / Completed Info */}
      <div className="mb-4 flex flex-wrap gap-2">
        {completedCounters.map((c, i) => (
          <div key={i} className="bg-emerald-500/10 border border-emerald-500/30 rounded-xl px-3 py-2 flex items-center gap-2 animate-in slide-in-from-top-2">
            <span className="text-xs font-black text-emerald-500 uppercase">{c.type}</span>
            <span className="font-bold text-white">{c.value}</span>
            <button onClick={() => removeCounter(i)} className="text-slate-500 hover:text-white">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6" />
              </svg>
            </button>
          </div>
        ))}
        {!isDynamic && requiredTypes.map(type => {
          if (completedCounters.find(c => c.type === type)) return null;
          return (
            <div key={type} className={`px-3 py-2 rounded-xl border-2 border-dashed ${selectedType === type ? 'border-orange-500/50 bg-orange-500/5' : 'border-slate-700 bg-slate-800/50'} text-xs font-black flex items-center gap-1`}>
              <span className={selectedType === type ? 'text-orange-500' : 'text-slate-500'}>ממתין ל{type}</span>
            </div>
          );
        })}
      </div>

      {/* Type Selector (Enabled only if dynamic) */}
      <div className="flex gap-2 mb-4">
        {COUNTER_TYPES.map(type => {
          const isRequired = requiredTypes.includes(type);
          const isDone = !!completedCounters.find(c => c.type === type);
          const isDisabled = !isDynamic && !isRequired;

          return (
            <button
              key={type}
              disabled={isDisabled || isDone}
              onClick={() => setSelectedType(type)}
              className={`flex-1 py-3 rounded-2xl text-lg font-black transition-all border-2 ${
                selectedType === type 
                  ? 'bg-orange-500 border-orange-400 text-white shadow-lg' 
                  : isDone 
                  ? 'bg-emerald-900/20 border-emerald-900/40 text-emerald-500/50' 
                  : isDisabled 
                  ? 'bg-slate-900/50 border-slate-800 text-slate-700'
                  : 'bg-slate-800 border-slate-700 text-slate-400'
              }`}
            >
              {type}
            </button>
          );
        })}
      </div>

      <div className="bg-slate-800 rounded-3xl p-6 mb-4 border-2 border-slate-700 flex flex-col items-center">
        <div className="flex items-center justify-center gap-4 w-full">
          <div className={`text-6xl font-black tracking-widest tabular-nums ${currentValue ? 'text-white' : 'text-slate-600'}`}>
            {currentValue || '00000'}
          </div>
          {isDynamic && (
            <button 
              onClick={addCounter}
              disabled={!isValidEntry}
              className={`w-14 h-14 rounded-xl flex items-center justify-center transition-all ${isValidEntry ? 'bg-emerald-500 text-white active:scale-90 shadow-lg' : 'bg-slate-700 text-slate-500'}`}
            >
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M12 4v16m8-8H4" />
              </svg>
            </button>
          )}
        </div>
      </div>

      {/* Industrial Custom Numpad */}
      <div className="flex-1 grid grid-cols-3 gap-2 pb-4">
        {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
          <button 
            key={num} 
            onClick={() => handleKeyPress(num.toString())}
            className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-600 border-b-4 border-slate-900"
          >
            {num}
          </button>
        ))}
        <button className="bg-slate-800/40 rounded-2xl"></button>
        <button 
          onClick={() => handleKeyPress('0')}
          className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-600 border-b-4 border-slate-900"
        >
          0
        </button>
        <button 
          onClick={handleDelete}
          className="bg-red-900/40 rounded-2xl text-3xl font-bold text-red-400 active:bg-red-800 border-b-4 border-slate-900 flex items-center justify-center"
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2M3 12l6.414 6.414a2 2 0 001.414.586H19a2 2 0 002-2V7a2 2 0 00-2-2h-8.172a2 2 0 00-1.414.586L3 12z" />
          </svg>
        </button>
      </div>

      <button
        disabled={!allRequiredMet}
        onClick={handleFinalConfirm}
        className={`w-full py-8 rounded-3xl text-3xl font-black transition-all shadow-xl active:scale-95 ${
          allRequiredMet ? 'bg-orange-500 text-white shadow-orange-500/20' : 'bg-slate-800 text-slate-600 grayscale cursor-not-allowed'
        }`}
      >
        {isDynamic ? 'אישור וסיום דיווח' : (completedCounters.length < requiredTypes.length - 1 ? 'שמור והמשך למונה הבא' : 'אישור וסיום דיווח')}
      </button>
    </div>
  );
};

export default DataEntryScreen;

