import React, { useState, useEffect } from 'react';
import { Extinguisher, CounterType, CounterValue } from '../types';

interface DataEntryScreenProps {
  onConfirm: (counters: CounterValue[]) => void;
  onBack: () => void;
  extinguisher: Extinguisher | null;
}

const COUNTER_TYPES: CounterType[] = ['שע"מ', 'ק"מ', 'מייל'];

const DataEntryScreen: React.FC<DataEntryScreenProps> = ({ onConfirm, onBack, extinguisher }) => {
  // Use a dictionary to keep track of the input for each specific type
  const [drafts, setDrafts] = useState<Record<CounterType, string>>({
    'שע"מ': '',
    'ק"מ': '',
    'מייל': ''
  });
  const [selectedType, setSelectedType] = useState<CounterType>('שע"מ');

  // Determine requirements from "server"
  const requiredTypes = extinguisher?.requiredCounters || [];
  const isDynamic = extinguisher?.isNew || requiredTypes.length === 0;

  // Auto-select first required type on load if not dynamic
  useEffect(() => {
    if (!isDynamic && requiredTypes.length > 0) {
      setSelectedType(requiredTypes[0]);
    }
  }, [extinguisher]);

  const currentValue = drafts[selectedType];
  const isValidEntry = (val: string) => val.length >= 2;

  const handleKeyPress = (num: string) => {
    setDrafts(prev => {
      const current = prev[selectedType];
      if (current.length < 8) {
        return { ...prev, [selectedType]: current + num };
      }
      return prev;
    });
  };

  const handleDelete = () => {
    setDrafts(prev => ({
      ...prev,
      [selectedType]: prev[selectedType].slice(0, -1)
    }));
  };

  const handleClear = () => {
    setDrafts(prev => ({
      ...prev,
      [selectedType]: ''
    }));
  };

  // Logic for finishing: 
  // If static: All required types must have a valid value.
  // If dynamic: At least one type must have a valid value.
  const allRequiredMet = isDynamic 
    ? Object.values(drafts).some(isValidEntry)
    : requiredTypes.every(type => isValidEntry(drafts[type]));

  const handleFinalConfirm = () => {
    const finalCounters: CounterValue[] = (Object.keys(drafts) as CounterType[])
      .filter(type => isValidEntry(drafts[type]))
      .map(type => ({ type, value: drafts[type] }));

    onConfirm(finalCounters);
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in zoom-in-95 duration-500">
      <div className="mb-4 flex items-start justify-between">
        <div>
          <h2 className="text-4xl font-black text-white leading-tight">דיווח מונים</h2>
          <p className="text-slate-400 text-lg mt-1 font-bold italic">
            הזן נתונים עבור <span className="text-orange-400">{extinguisher?.name}</span>
          </p>
        </div>
        <button onClick={onBack} className="p-4 bg-slate-800 rounded-2xl active:bg-slate-700 transition-colors">
          <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Required Status Indicators */}
      {!isDynamic && (
        <div className="mb-4 flex gap-2">
          {requiredTypes.map(type => {
            const isFilled = isValidEntry(drafts[type]);
            const isCurrentlySelected = selectedType === type;
            return (
              <div 
                key={type} 
                className={`flex-1 p-2 rounded-xl border-2 transition-all flex flex-col items-center justify-center ${
                  isFilled 
                    ? 'bg-emerald-500/10 border-emerald-500/50' 
                    : isCurrentlySelected 
                    ? 'bg-orange-500/10 border-orange-500/50' 
                    : 'bg-slate-800 border-slate-700'
                }`}
              >
                <span className={`text-[10px] font-black uppercase ${isFilled ? 'text-emerald-500' : isCurrentlySelected ? 'text-orange-500' : 'text-slate-500'}`}>
                  {type} {isFilled ? '✓' : ''}
                </span>
                <span className={`text-sm font-bold ${isFilled ? 'text-white' : 'text-slate-600'}`}>
                  {isFilled ? drafts[type] : '---'}
                </span>
              </div>
            );
          })}
        </div>
      )}

      {/* Type Selector Tabs */}
      <div className="flex gap-2 mb-4">
        {COUNTER_TYPES.map(type => {
          const isRequired = requiredTypes.includes(type);
          const hasValue = isValidEntry(drafts[type]);
          const isDisabled = !isDynamic && !isRequired;

          return (
            <button
              key={type}
              disabled={isDisabled}
              onClick={() => setSelectedType(type)}
              className={`flex-1 py-4 rounded-2xl text-xl font-black transition-all border-2 relative ${
                selectedType === type 
                  ? 'bg-orange-500 border-orange-400 text-white shadow-lg shadow-orange-500/20' 
                  : isDisabled 
                  ? 'bg-slate-900/50 border-slate-800 text-slate-700 opacity-50'
                  : hasValue 
                  ? 'bg-emerald-900/30 border-emerald-800 text-emerald-400'
                  : 'bg-slate-800 border-slate-700 text-slate-400'
              }`}
            >
              {type}
              {hasValue && selectedType !== type && (
                <div className="absolute -top-1 -left-1 w-5 h-5 bg-emerald-500 rounded-full flex items-center justify-center border-2 border-slate-900">
                  <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
                  </svg>
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Big Number Input Display */}
      <div className="bg-slate-800 rounded-3xl p-6 mb-4 border-2 border-slate-700 relative overflow-hidden group">
        <div className="absolute top-3 right-4 text-[10px] font-black text-slate-500 uppercase tracking-widest">
          מזין כעת: {selectedType}
        </div>
        <div className="flex items-center justify-center gap-6 w-full py-2">
          <div className={`text-6xl font-black tracking-widest tabular-nums transition-all ${currentValue ? 'text-white' : 'text-slate-600'}`}>
            {currentValue || '00000'}
          </div>
          {currentValue && (
            <button 
              onClick={handleClear}
              className="text-slate-500 hover:text-red-400 p-2 transition-colors"
              title="נקה"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          )}
        </div>
      </div>

      {/* Numpad Grid */}
      <div className="flex-1 grid grid-cols-3 gap-2 pb-4">
        {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
          <button 
            key={num} 
            onClick={() => handleKeyPress(num.toString())}
            className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-600 border-b-4 border-slate-950 transition-all active:translate-y-1 active:border-b-0"
          >
            {num}
          </button>
        ))}
        <div className="invisible" />
        <button 
          onClick={() => handleKeyPress('0')}
          className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-600 border-b-4 border-slate-950 transition-all active:translate-y-1 active:border-b-0"
        >
          0
        </button>
        <button 
          onClick={handleDelete}
          className="bg-red-900/40 rounded-2xl text-3xl font-bold text-red-400 active:bg-red-800 border-b-4 border-slate-950 flex items-center justify-center transition-all active:translate-y-1 active:border-b-0"
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2M3 12l6.414 6.414a2 2 0 001.414.586H19a2 2 0 002-2V7a2 2 0 00-2-2h-8.172a2 2 0 00-1.414.586L3 12z" />
          </svg>
        </button>
      </div>

      {/* Footer Action Button */}
      <button
        disabled={!allRequiredMet}
        onClick={handleFinalConfirm}
        className={`w-full py-8 rounded-3xl text-3xl font-black transition-all shadow-xl active:scale-95 border-b-4 ${
          allRequiredMet 
            ? 'bg-orange-500 text-white shadow-orange-500/20 border-orange-700' 
            : 'bg-slate-800 text-slate-600 grayscale cursor-not-allowed border-slate-900'
        }`}
      >
        אישור וסיום דיווח
      </button>
    </div>
  );
};

