import React, { useState } from 'react';
import { FlowStep, ActionType, Extinguisher, BatchStats, CounterValue } from './types';
import TriggerScreen from './components/TriggerScreen';
import IdentifyScreen from './components/IdentifyScreen';
import DataEntryScreen from './components/DataEntryScreen';
import SuccessScreen from './components/SuccessScreen';
import AuditScreen from './components/AuditScreen';
import AuditSummaryScreen from './components/AuditSummaryScreen';
import NextVehicleScreen from './components/NextVehicleScreen';
import BatchSummaryScreen from './components/BatchSummaryScreen';

// Each vehicle now has exactly one extinguisher as per user requirement
const MOCK_EXTINGUISHERS: Extinguisher[] = [
  { id: '1', name: 'מטף ראשי', serialNumber: 'צד"י 12345', status: null, counters: [], requiredCounters: ['שע"מ', 'ק"מ'] },
];

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<FlowStep>(FlowStep.TRIGGER);
  const [action, setAction] = useState<ActionType | null>(null);
  const [selectedExtinguisher, setSelectedExtinguisher] = useState<Extinguisher | null>(null);
  const [currentVehicleId, setCurrentVehicleId] = useState('123456');

  const [auditList, setAuditList] = useState<Extinguisher[]>(MOCK_EXTINGUISHERS);
  const [batchStats, setBatchStats] = useState<BatchStats>({
    vehiclesCount: 0,
    extinguishersChecked: 0,
    anomaliesFound: 0
  });

  const handleActionSelect = (type: ActionType) => {
    setAction(type);
    if (type === ActionType.AUDIT) {
      setAuditList(MOCK_EXTINGUISHERS.map(e => ({ ...e, status: null, actualSerialNumber: '' })));
      setCurrentStep(FlowStep.AUDIT_CHECK);
    } else {
      setCurrentStep(FlowStep.IDENTIFY);
    }
  };

  const handleExtinguisherSelect = (ext: Extinguisher) => {
    setSelectedExtinguisher(ext);
    setCurrentStep(FlowStep.DATA_ENTRY);
  };

  const handleAuditFinish = () => {
    setCurrentStep(FlowStep.AUDIT_SUMMARY);
  };

  const handleAuditFinalSubmit = (mileage: string) => {
    const anomalies = auditList.filter(e => e.status === 'anomaly').length;
    setBatchStats(prev => ({
      vehiclesCount: prev.vehiclesCount + 1,
      extinguishersChecked: prev.extinguishersChecked + auditList.length,
      anomaliesFound: prev.anomaliesFound + anomalies
    }));
    setCurrentStep(FlowStep.NEXT_VEHICLE);
  };

  const handleNewVehicle = (newId: string) => {
    setCurrentVehicleId(newId);
    setAuditList(MOCK_EXTINGUISHERS.map(e => ({ ...e, status: null, actualSerialNumber: '' })));
    setCurrentStep(FlowStep.AUDIT_CHECK);
  };

  const handleReset = () => {
    setAction(null);
    setSelectedExtinguisher(null);
    setCurrentStep(FlowStep.TRIGGER);
  };

  const renderStep = () => {
    switch (currentStep) {
      case FlowStep.TRIGGER:
        return <TriggerScreen onSelect={handleActionSelect} />;
      case FlowStep.IDENTIFY:
        return (
          <IdentifyScreen 
            extinguishers={MOCK_EXTINGUISHERS} 
            onSelect={handleExtinguisherSelect}
            onBack={handleReset}
          />
        );
      case FlowStep.DATA_ENTRY:
        return (
          <DataEntryScreen 
            onConfirm={(counters: CounterValue[]) => {
              if (selectedExtinguisher) {
                setSelectedExtinguisher({ ...selectedExtinguisher, counters });
              }
              setCurrentStep(FlowStep.SUCCESS);
            }}
            onBack={() => setCurrentStep(FlowStep.IDENTIFY)}
            extinguisher={selectedExtinguisher}
          />
        );
      case FlowStep.AUDIT_CHECK:
        return (
          <AuditScreen 
            items={auditList} 
            setItems={setAuditList} 
            onFinish={handleAuditFinish} 
            onBack={handleReset}
            vehicleId={currentVehicleId}
          />
        );
      case FlowStep.AUDIT_SUMMARY:
        return (
          <AuditSummaryScreen 
            items={auditList} 
            onConfirm={handleAuditFinalSubmit}
            onBack={() => setCurrentStep(FlowStep.AUDIT_CHECK)}
          />
        );
      case FlowStep.NEXT_VEHICLE:
        return (
          <NextVehicleScreen 
            onNext={handleNewVehicle} 
            onFinishBatch={() => setCurrentStep(FlowStep.BATCH_SUMMARY)} 
          />
        );
      case FlowStep.BATCH_SUMMARY:
        return <BatchSummaryScreen stats={batchStats} onFinish={handleReset} />;
      case FlowStep.SUCCESS:
        return (
          <SuccessScreen 
            extinguisher={selectedExtinguisher}
            onFinish={handleReset} 
          />
        );
      default:
        return <TriggerScreen onSelect={handleActionSelect} />;
    }
  };

  return (
    <div className="h-screen w-full flex flex-col bg-[#0F172A] text-slate-100 overflow-hidden font-['Assistant']">
      <header className="px-6 py-4 flex justify-between items-center border-b border-slate-800 bg-[#1E293B]">
        <div className="flex flex-col">
          <h1 className="text-xs uppercase tracking-widest text-slate-400 font-bold">ניהול אמצעי כיבוי</h1>
          <p className="text-lg font-extrabold text-white">כלי: {currentVehicleId}</p>
        </div>
        <div className="flex items-center gap-3">
           <div className="hidden md:block text-left">
              <p className="text-xs text-slate-400 font-bold">טכנאי מורשה</p>
              <p className="text-sm font-bold">אלכס ב.</p>
           </div>
           <div className="w-10 h-10 rounded-full bg-orange-500/20 border border-orange-500 flex items-center justify-center">
             <span className="text-sm font-extrabold text-orange-500">א"ב</span>
           </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto relative p-6">
        {renderStep()}
      </main>

      <div className="px-6 pb-6 flex gap-2">
        {Object.values(FlowStep).slice(0, 4).map((step, idx) => {
          const isActive = currentStep === step || 
            (currentStep.startsWith('AUDIT') && idx === 1) || 
            (currentStep === FlowStep.NEXT_VEHICLE && idx === 2);
          return (
            <div 
              key={step} 
              className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
                isActive ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.5)]' : 'bg-slate-800'
              }`} 
            />
          );
        })}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Extinguisher } from '../types';

interface AuditScreenProps {
  items: Extinguisher[];
  setItems: React.Dispatch<React.SetStateAction<Extinguisher[]>>;
  onFinish: () => void;
  onBack: () => void;
  vehicleId: string;
}

const GLOBAL_EXTINGUISHERS_POOL = [
  'צד"י 11111', 'צד"י 22222', 'צד"י 33333', 'צד"י 44444', 'צד"י 55555',
  'צד"י 12345', 'צד"י 67890', 'צד"י 11223', 'צד"י 99999', 'צד"י 88888'
];

const AuditScreen: React.FC<AuditScreenProps> = ({ items, setItems, onFinish, onBack, vehicleId }) => {
  // Track which item is currently showing suggestions
  const [showSuggestionsFor, setShowSuggestionsFor] = useState<string | null>(null);

  const toggleStatus = (id: string, status: 'ok' | 'anomaly') => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, status, actualSerialNumber: status === 'ok' ? '' : item.actualSerialNumber } : item
    ));
    if (status === 'anomaly') {
      setShowSuggestionsFor(id);
    } else {
      setShowSuggestionsFor(null);
    }
  };

  const updateActualId = (id: string, actualId: string, fromSuggestion = false) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, actualSerialNumber: actualId } : item));
    if (fromSuggestion) {
      setShowSuggestionsFor(null); // Close list when a suggestion is picked
    }
  };

  const allChecked = items.every(i => i.status === 'ok' || (i.status === 'anomaly' && i.actualSerialNumber && i.actualSerialNumber.length > 2));

  return (
    <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500">
      <div className="mb-6 flex items-start justify-between">
        <div>
          <h2 className="text-4xl font-black text-white leading-tight">אימות מטפים</h2>
          <p className="text-slate-400 text-lg mt-1 font-bold italic">כלי: {vehicleId}</p>
        </div>
        <button onClick={onBack} className="p-4 bg-slate-800 rounded-2xl active:bg-slate-700 transition-colors">
          <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-4 overflow-y-auto pr-1">
        {items.map((item) => (
          <div key={item.id} className="bg-slate-800 border-2 border-slate-700 rounded-3xl p-5 flex flex-col gap-4 shadow-xl">
            <div className="flex items-center justify-between w-full">
              <div>
                <div className="text-2xl font-black text-white">{item.name}</div>
                <div className="text-slate-400 font-bold uppercase text-sm tracking-widest">{item.serialNumber}</div>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => toggleStatus(item.id, 'anomaly')}
                  className={`w-16 h-16 rounded-2xl flex items-center justify-center border-2 transition-all ${
                    item.status === 'anomaly' ? 'bg-red-600 border-red-400 scale-105 shadow-lg shadow-red-900/40' : 'bg-slate-900 border-slate-700'
                  }`}
                >
                  <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>

                <button 
                  onClick={() => toggleStatus(item.id, 'ok')}
                  className={`w-16 h-16 rounded-2xl flex items-center justify-center border-2 transition-all ${
                    item.status === 'ok' ? 'bg-emerald-600 border-emerald-400 scale-105 shadow-lg shadow-emerald-900/40' : 'bg-slate-900 border-slate-700'
                  }`}
                >
                  <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
                  </svg>
                </button>
              </div>
            </div>

            {item.status === 'anomaly' && (
              <div className="animate-in slide-in-from-top-2 duration-300">
                <label className="block text-slate-400 text-sm font-bold mb-2 mr-1">הזן מספר צד״י של המטף שנמצא בפועל:</label>
                <div className="relative">
                  <input 
                    type="text"
                    placeholder="הקלד מספר צד״י..."
                    value={item.actualSerialNumber || ''}
                    onFocus={() => setShowSuggestionsFor(item.id)}
                    onChange={(e) => {
                      updateActualId(item.id, e.target.value);
                      setShowSuggestionsFor(item.id);
                    }}
                    className="w-full bg-slate-900 border-2 border-slate-600 rounded-2xl p-4 text-xl font-bold text-white outline-none focus:border-red-500 transition-all"
                  />

                  {showSuggestionsFor === item.id && item.actualSerialNumber && item.actualSerialNumber.length > 0 && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-2xl z-20 max-h-48 overflow-y-auto">
                      {GLOBAL_EXTINGUISHERS_POOL
                        .filter(s => s.toLowerCase().includes(item.actualSerialNumber!.toLowerCase()))
                        .map(suggestion => (
                          <button
                            key={suggestion}
                            onClick={() => updateActualId(item.id, suggestion, true)}
                            className="w-full p-4 text-right hover:bg-slate-800 text-slate-200 font-bold border-b border-slate-800 last:border-0 transition-colors"
                          >
                            {suggestion}
                          </button>
                        ))}
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>

      <button
        disabled={!allChecked}
        onClick={onFinish}
        className={`mt-6 w-full py-6 rounded-3xl text-2xl font-black transition-all shadow-xl ${
          allChecked ? 'bg-orange-500 text-white shadow-orange-500/20 border-b-4 border-orange-700 active:translate-y-1 active:border-b-0' : 'bg-slate-800 text-slate-600 grayscale cursor-not-allowed'
        }`}
      >
        סיום אימות
      </button>
    </div>
  );
};

