  const [activeDistanceUnit, setActiveDistanceUnit] = useState<'ק"מ' | 'מייל'>('ק"מ');

  const requiredTypes = extinguisher?.requiredCounters || [];
  const isDynamic = extinguisher?.isNew || requiredTypes.length === 0;

  useEffect(() => {
    if (!isDynamic && requiredTypes.length > 0) {
      if (requiredTypes.includes('שע"מ')) setSelectedType('שע"מ');
      else setSelectedType(requiredTypes[0] as CounterType);

      if (requiredTypes.includes('מייל')) setActiveDistanceUnit('מייל');
    }
  }, [extinguisher]);

  const currentValue = drafts[selectedType];
  const isValidEntry = (val: string) => val.length >= 2;

  const handleKeyPress = (num: string) => {
    setDrafts(prev => {
      const current = prev[selectedType];
      if (current.length < 8) {
        return { ...prev, [selectedType]: current + num };
      }
      return prev;
    });
  };

  const handleDelete = () => {
    setDrafts(prev => ({
      ...prev,
      [selectedType]: prev[selectedType].slice(0, -1)
    }));
  };

  const handleClear = () => {
    setDrafts(prev => ({
      ...prev,
      [selectedType]: ''
    }));
  };

