    setSelectedType(type);
    if (type === 'ק"מ' || type === 'מייל') {
      setActiveDistanceUnit(type);
    }
  };

  // Validation: Must have Engine Hours (if required) AND exactly one distance unit (if required)
  const isEngineHoursMet = !requiredTypes.includes('שע"מ') || isValidEntry(drafts['שע"מ']);
  const isDistanceMet = isDynamic 
    ? (isValidEntry(drafts['ק"מ']) || isValidEntry(drafts['מייל']) || isValidEntry(drafts['שע"מ']))
    : isValidEntry(drafts[activeDistanceUnit]);

  const canConfirm = isEngineHoursMet && isDistanceMet;

  const handleFinalConfirm = () => {
    const finalCounters: CounterValue[] = [];

    // Always add Engine Hours if filled
    if (isValidEntry(drafts['שע"מ'])) {
      finalCounters.push({ type: 'שע"מ', value: drafts['שע"מ'] });
    }

    // Add ONLY the active distance unit
    if (isValidEntry(drafts[activeDistanceUnit])) {
      finalCounters.push({ type: activeDistanceUnit, value: drafts[activeDistanceUnit] });
