        </button>
      </div>

      {/* Structured Selection Layout */}
      <div className="grid grid-cols-2 gap-3 mb-4 shrink-0">
        {/* Engine Hours Tab - Always visible if relevant */}
        <button
          onClick={() => handleTypeSelect('שע"מ')}
          className={`flex flex-col items-center py-3 px-2 rounded-2xl border-2 transition-all ${
            selectedType === 'שע"מ' 
              ? 'bg-orange-500 border-orange-400 text-white shadow-lg' 
              : isValidEntry(drafts['שע"מ']) 
              ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-500' 
              : 'bg-slate-800 border-slate-700 text-slate-500'
          }`}
        >
          <span className="text-xs font-black mb-1">שעות מנוע</span>
          <span className={`text-lg font-black tabular-nums ${selectedType === 'שע"מ' ? 'text-white' : 'text-slate-400'}`}>
            {drafts['שע"מ'] || '---'}
