import React, { useState, useEffect } from 'react';
import { Extinguisher, CounterType, CounterValue } from '../types';

interface DataEntryScreenProps {
  onConfirm: (counters: CounterValue[]) => void;
  onBack: () => void;
  extinguisher: Extinguisher | null;
}

const DataEntryScreen: React.FC<DataEntryScreenProps> = ({ onConfirm, onBack, extinguisher }) => {
  const [drafts, setDrafts] = useState<Record<CounterType, string>>({
    'שע"מ': '',
    'ק"מ': '',
    'מייל': ''
  });

  // The user is either editing 'שע"מ' or the 'distance' unit
  const [editingCategory, setEditingCategory] = useState<'hours' | 'distance'>('hours');

  // The strictly chosen distance unit
  const [selectedDistanceUnit, setSelectedDistanceUnit] = useState<'ק"מ' | 'מייל' | null>(null);

  const requiredTypes = extinguisher?.requiredCounters || [];
  const isDynamic = extinguisher?.isNew || requiredTypes.length === 0;

  useEffect(() => {
    // If only one distance unit is required, lock it automatically
    const hasKm = requiredTypes.includes('ק"מ');
    const hasMiles = requiredTypes.includes('מייל');

    if (hasKm && !hasMiles) setSelectedDistanceUnit('ק"מ');
    else if (hasMiles && !hasKm) setSelectedDistanceUnit('מייל');
    else if (!isDynamic && hasKm && hasMiles) {
      // Server sent both? Don't auto-select, force user to choose
      setSelectedDistanceUnit(null);
    }

    // Auto-focus hours if required, otherwise focus distance if we have a unit
    if (requiredTypes.includes('שע"מ')) {
      setEditingCategory('hours');
    } else if (selectedDistanceUnit) {
      setEditingCategory('distance');
    }
  }, [extinguisher, isDynamic]);

  const activeType: CounterType = editingCategory === 'hours' ? 'שע"מ' : (selectedDistanceUnit || 'ק"מ');
  const currentValue = drafts[activeType];

  const isValidEntry = (val: string) => val.length >= 2;

  const handleKeyPress = (num: string) => {
    if (editingCategory === 'distance' && !selectedDistanceUnit) return;

    setDrafts(prev => {
      const current = prev[activeType];
      if (current.length < 8) {
        return { ...prev, [activeType]: current + num };
      }
      return prev;
    });
  };

  const handleDelete = () => {
    setDrafts(prev => ({
      ...prev,
      [activeType]: prev[activeType].slice(0, -1)
    }));
  };

  const handleClear = () => {
    setDrafts(prev => ({
      ...prev,
      [activeType]: ''
    }));
  };

  // Check if reporting is ready
  const isEngineHoursValid = !requiredTypes.includes('שע"מ') || isValidEntry(drafts['שע"מ']);
  const isDistanceValid = selectedDistanceUnit ? isValidEntry(drafts[selectedDistanceUnit]) : false;

  // In dynamic mode, user can report just hours OR just distance, but distance must have a unit
  const canConfirm = isDynamic 
    ? (isValidEntry(drafts['שע"מ']) || (selectedDistanceUnit && isValidEntry(drafts[selectedDistanceUnit])))
    : (isEngineHoursValid && isDistanceValid);

  const handleFinalConfirm = () => {
    const finalCounters: CounterValue[] = [];
    if (isValidEntry(drafts['שע"מ'])) finalCounters.push({ type: 'שע"מ', value: drafts['שע"מ'] });
    if (selectedDistanceUnit && isValidEntry(drafts[selectedDistanceUnit])) {
      finalCounters.push({ type: selectedDistanceUnit, value: drafts[selectedDistanceUnit] });
    }
    onConfirm(finalCounters);
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in slide-in-from-bottom-4 duration-500 overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div>
          <h2 className="text-3xl font-black text-white">{extinguisher?.name}</h2>
          <p className="text-slate-500 font-bold text-sm">הזנת קריאות - {isDynamic ? 'מטף חדש' : 'כלי קיים'}</p>
        </div>
        <button onClick={onBack} className="p-3 bg-slate-800 rounded-xl text-slate-400">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Inputs Selector Area */}
      <div className="space-y-3 mb-4">
        {/* Engine Hours Row */}
        {(requiredTypes.includes('שע"מ') || isDynamic) && (
          <button
            onClick={() => setEditingCategory('hours')}
            className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${
              editingCategory === 'hours' 
                ? 'bg-orange-500 border-orange-400 text-white shadow-lg' 
                : 'bg-slate-800 border-slate-700 text-slate-400'
            }`}
          >
            <span className="text-lg font-black">שעות מנוע (שע"מ)</span>
            <span className="text-2xl font-black tabular-nums">{drafts['שע"מ'] || '---'}</span>
          </button>
        )}

        {/* Distance Choice Area */}
        <div className={`p-4 rounded-2xl border-2 transition-all ${
          editingCategory === 'distance' 
            ? 'bg-slate-800 border-orange-500' 
            : 'bg-slate-900 border-slate-800'
        }`}>
          <div className="flex items-center justify-between mb-3">
             <span className={`text-sm font-black uppercase tracking-widest ${editingCategory === 'distance' ? 'text-orange-400' : 'text-slate-600'}`}>
               מרחק נסיעה
             </span>
             {/* Unit Switcher - Only shows if allowed/required */}
             {(isDynamic || (requiredTypes.includes('ק"מ') && requiredTypes.includes('מייל'))) && (
               <div className="flex bg-slate-950 p-1 rounded-xl gap-1">
                 {['ק"מ', 'מייל'].map(unit => (
                   <button
                     key={unit}
                     onClick={(e) => {
                       e.stopPropagation();
                       setSelectedDistanceUnit(unit as any);
                       setEditingCategory('distance');
                     }}
                     className={`px-3 py-1 rounded-lg text-xs font-black transition-all ${
                       selectedDistanceUnit === unit 
                        ? 'bg-orange-500 text-white' 
                        : 'text-slate-500 hover:text-slate-300'
                     }`}
                   >
                     {unit}
                   </button>
                 ))}
               </div>
             )}
          </div>

          <button
            onClick={() => setEditingCategory('distance')}
            disabled={!selectedDistanceUnit}
            className={`w-full flex items-center justify-between p-2 rounded-xl transition-all ${
              !selectedDistanceUnit ? 'opacity-30' : ''
            }`}
          >
            <span className={`text-xl font-bold ${editingCategory === 'distance' ? 'text-white' : 'text-slate-500'}`}>
              {selectedDistanceUnit ? `קריאה ב-${selectedDistanceUnit}` : 'בחר יחידת מידה'}
            </span>
            <span className={`text-3xl font-black tabular-nums ${editingCategory === 'distance' ? 'text-white' : 'text-slate-600'}`}>
              {selectedDistanceUnit ? (drafts[selectedDistanceUnit] || '---') : ''}
            </span>
          </button>
        </div>
      </div>

      {/* Main Display Area */}
      <div className="bg-slate-800/80 rounded-3xl border-2 border-slate-700 p-6 mb-4 text-center shrink-0">
        <div className="text-xs font-black text-slate-500 uppercase mb-1">
          {editingCategory === 'hours' ? 'מזין שעות מנוע' : selectedDistanceUnit ? `מזין ק"מ/מייל (${selectedDistanceUnit})` : 'בחר שדה להזנה'}
        </div>
        <div className="flex items-center justify-center gap-4">
          <span className={`text-6xl font-black tabular-nums ${currentValue ? 'text-white' : 'text-slate-700'}`}>
            {currentValue || '00000'}
          </span>
          {currentValue && (
            <button onClick={handleClear} className="text-slate-600 active:text-red-400 p-2">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          )}
        </div>
      </div>

      {/* Numpad */}
      <div className="flex-1 grid grid-cols-3 gap-2 mb-4">
        {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
          <button 
            key={num} 
            onClick={() => handleKeyPress(num.toString())}
            className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-700 border-b-4 border-slate-950 flex items-center justify-center"
          >
            {num}
          </button>
        ))}
        <button className="invisible" />
        <button 
          onClick={() => handleKeyPress('0')}
          className="bg-slate-800 rounded-2xl text-3xl font-bold text-white active:bg-slate-700 border-b-4 border-slate-950 flex items-center justify-center"
        >
          0
        </button>
        <button 
          onClick={handleDelete}
          className="bg-slate-800 rounded-2xl text-red-400 active:bg-red-900/20 border-b-4 border-slate-950 flex items-center justify-center"
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2M3 12l6.414 6.414a2 2 0 001.414.586H19a2 2 0 002-2V7a2 2 0 00-2-2h-8.172a2 2 0 00-1.414.586L3 12z" />
          </svg>
        </button>
      </div>

      {/* Submit */}
      <button
