            ? 'bg-orange-500 text-white shadow-xl shadow-orange-500/20 border-orange-700 active:translate-y-1 active:border-b-0' 
            : 'bg-slate-800 text-slate-600 border-slate-900 grayscale cursor-not-allowed'
