import React, { useState, useMemo } from 'react';
import { Extinguisher } from '../types';

interface IdentifyScreenProps {
  extinguishers: Extinguisher[];
  onSelect: (ext: Extinguisher) => void;
  onBack: () => void;
}

// Simulated pool of all known extinguishers in the organization
const GLOBAL_POOL: Partial<Extinguisher>[] = [
  { serialNumber: 'S-1001', name: 'מטף אבקה 6 ק"ג', materialNumber: 'MAT-100' },
  { serialNumber: 'S-1002', name: 'מטף אבקה 6 ק"ג', materialNumber: 'MAT-100' },
  { serialNumber: 'S-2001', name: 'מטף הלון 2.5 ק"ג', materialNumber: 'MAT-200' },
  { serialNumber: 'S-2002', name: 'מטף הלון 2.5 ק"ג', materialNumber: 'MAT-200' },
  { serialNumber: 'S-9999', name: 'מטף קצף 9 ליטר', materialNumber: 'MAT-900' },
];

const IdentifyScreen: React.FC<IdentifyScreenProps> = ({ extinguishers, onSelect, onBack }) => {
  const [manualSerial, setManualSerial] = useState('');
  const [manualMaterial, setManualMaterial] = useState('');
  const [isNewItem, setIsNewItem] = useState(false);

  const suggestions = useMemo(() => {
    if (!manualSerial || manualSerial.length < 2) return [];
    return GLOBAL_POOL.filter(item => 
      item.serialNumber?.toLowerCase().includes(manualSerial.toLowerCase())
    );
  }, [manualSerial]);

  const handleSuggestionClick = (item: Partial<Extinguisher>) => {
    onSelect({
      id: Date.now().toString(),
      name: item.name || 'מטף מזוהה',
      serialNumber: item.serialNumber!,
      materialNumber: item.materialNumber,
      counters: [],
      requiredCounters: [],
      isNew: false
    });
  };

  const handleManualSubmit = () => {
    // Check if it already exists in suggestions (exact match)
    const exactMatch = GLOBAL_POOL.find(i => i.serialNumber === manualSerial);

    if (exactMatch) {
      handleSuggestionClick(exactMatch);
      return;
    }

    // If not exists and we haven't asked for material yet
    if (!isNewItem) {
      setIsNewItem(true);
      return;
    }

    // If we have both serial and material for a new item
    if (manualSerial && manualMaterial) {
      onSelect({ 
        id: Date.now().toString(), 
        name: 'מטף חדש', 
        serialNumber: manualSerial.trim(),
        materialNumber: manualMaterial.trim(),
        counters: [],
        requiredCounters: [], 
        isNew: true
      });
    }
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-4 duration-500 overflow-hidden">
      <div className="mb-6 flex items-start justify-between">
        <div>
          <h2 className="text-4xl font-black text-white leading-tight">זיהוי מטף</h2>
          <p className="text-slate-400 text-lg mt-1 font-bold">בחר מהרשימה או סרוק מס"ד</p>
        </div>
        <button onClick={onBack} className="p-4 bg-slate-800 rounded-2xl active:bg-slate-700">
          <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Recommended/Existing List */}
      <div className="flex-1 space-y-3 overflow-y-auto mb-6 pr-1">
        <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mr-2 mb-2">מטפים משויכים לכלי:</h3>
        {extinguishers.map((ext) => (
          <button
            key={ext.id}
            onClick={() => onSelect(ext)}
            className="w-full flex items-center p-5 bg-slate-800 border-2 border-slate-700 rounded-3xl active:bg-orange-600 active:border-orange-400 transition-all shadow-lg text-right group"
          >
            <div className="flex-1">
              <div className="text-xl font-black text-white">{ext.name}</div>
              <div className="flex gap-2 mt-1">
                <span className="bg-slate-900 px-2 py-0.5 rounded text-[10px] font-bold text-slate-400">מס"ד: {ext.serialNumber}</span>
                {ext.materialNumber && (
                  <span className="bg-slate-900 px-2 py-0.5 rounded text-[10px] font-bold text-orange-500/70 uppercase">מק"ט: {ext.materialNumber}</span>
                )}
              </div>
            </div>
            <div className="w-10 h-10 rounded-full bg-slate-700 flex items-center justify-center group-active:bg-white/20">
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" />
              </svg>
            </div>
          </button>
        ))}
      </div>

      {/* Manual Entry with Suggestions */}
      <div className={`mt-auto bg-slate-800/50 p-6 rounded-3xl border-2 transition-all duration-300 ${isNewItem ? 'border-orange-500 ring-4 ring-orange-500/10' : 'border-dashed border-slate-700'}`}>
        <div className="flex items-center justify-between mb-4">
          <label className="block text-slate-400 font-bold mr-2 text-sm uppercase tracking-tighter">
            {isNewItem ? 'זיהוי פריט חדש - הזן מק"ט' : 'הזנה ידנית של מספר מס"ד:'}
          </label>
          {isNewItem && (
            <button onClick={() => setIsNewItem(false)} className="text-xs text-orange-400 underline font-black">ביטול</button>
          )}
        </div>

        <div className="space-y-3 relative">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={manualSerial}
              readOnly={isNewItem}
              onChange={(e) => {
                setManualSerial(e.target.value);
                setIsNewItem(false);
              }}
              placeholder="הזן מס' מס״ד..."
              className={`flex-1 bg-slate-900 border-2 rounded-2xl p-4 text-xl font-bold text-white outline-none transition-all ${isNewItem ? 'border-emerald-500/50 opacity-60' : 'border-slate-700 focus:border-orange-500'}`}
            />
            {!isNewItem && (
              <button 
                onClick={handleManualSubmit}
                disabled={!manualSerial.trim()}
                className="bg-orange-500 disabled:bg-slate-700 text-white px-6 rounded-2xl active:scale-95 transition-all shadow-lg"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" />
                </svg>
              </button>
            )}
          </div>

          {/* New Item Material Field */}
          {isNewItem && (
            <div className="flex gap-2 animate-in slide-in-from-top-2 duration-300">
              <input 
                type="text" 
                autoFocus
                value={manualMaterial}
                onChange={(e) => setManualMaterial(e.target.value)}
                placeholder="הזן מק״ט (Material)..."
                className="flex-1 bg-slate-900 border-2 border-orange-500/50 rounded-2xl p-4 text-xl font-bold text-white outline-none focus:border-orange-500"
              />
              <button 
                onClick={handleManualSubmit}
                disabled={!manualMaterial.trim()}
                className="bg-emerald-500 disabled:bg-slate-700 text-white px-6 rounded-2xl active:scale-95 transition-all shadow-lg"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
                </svg>
              </button>
            </div>
          )}

          {/* Suggestions List */}
          {!isNewItem && suggestions.length > 0 && (
            <div className="absolute bottom-full left-0 right-0 mb-2 bg-slate-900 border border-slate-700 rounded-2xl overflow-hidden shadow-2xl z-50 animate-in fade-in slide-in-from-bottom-2">
              {suggestions.map((item) => (
                <button
                  key={item.serialNumber}
                  onClick={() => handleSuggestionClick(item)}
                  className="w-full p-4 text-right hover:bg-slate-800 text-white font-bold border-b border-slate-800 last:border-0 flex justify-between items-center"
                >
                  <div>
                    <span className="block text-sm">{item.name}</span>
                    <span className="text-xs text-orange-500">{item.serialNumber}</span>
                  </div>
                  <svg className="w-4 h-4 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
                  </svg>
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default IdentifyScreen;

import React, { useState, useEffect } from 'react';
import { Extinguisher, CounterType, CounterValue } from '../types';

interface DataEntryScreenProps {
  onConfirm: (counters: CounterValue[]) => void;
  onBack: () => void;
  extinguisher: Extinguisher | null;
}

const DataEntryScreen: React.FC<DataEntryScreenProps> = ({ onConfirm, onBack, extinguisher }) => {
  const [drafts, setDrafts] = useState<Record<CounterType, string>>({
    'שע"מ': '',
    'ק"מ': '',
    'מייל': ''
  });

  const [editingCategory, setEditingCategory] = useState<'hours' | 'distance'>('hours');
  const [selectedDistanceUnit, setSelectedDistanceUnit] = useState<'ק"מ' | 'מייל' | null>(null);

  const requiredTypes = extinguisher?.requiredCounters || [];
  const isDynamic = extinguisher?.isNew || requiredTypes.length === 0;

  useEffect(() => {
    const hasKm = requiredTypes.includes('ק"מ');
    const hasMiles = requiredTypes.includes('מייל');

    if (hasKm && !hasMiles) setSelectedDistanceUnit('ק"מ');
    else if (hasMiles && !hasKm) setSelectedDistanceUnit('מייל');
    else if (isDynamic) setSelectedDistanceUnit('ק"מ'); 

    if (requiredTypes.includes('שע"מ')) setEditingCategory('hours');
    else setEditingCategory('distance');
  }, [extinguisher, isDynamic]);

  const activeType: CounterType = editingCategory === 'hours' ? 'שע"מ' : (selectedDistanceUnit || 'ק"מ');
  const currentValue = drafts[activeType];

  const isValidEntry = (val: string) => val.length >= 2;

  const handleKeyPress = (num: string) => {
    if (editingCategory === 'distance' && !selectedDistanceUnit) return;
    setDrafts(prev => {
      const current = prev[activeType];
      if (current.length < 8) return { ...prev, [activeType]: current + num };
      return prev;
    });
  };

  const handleDelete = () => {
    setDrafts(prev => ({ ...prev, [activeType]: prev[activeType].slice(0, -1) }));
  };

  const handleClear = () => {
    setDrafts(prev => ({ ...prev, [activeType]: '' }));
  };

  const hasHoursValue = isValidEntry(drafts['שע"מ']);
  const hasDistanceValue = selectedDistanceUnit ? isValidEntry(drafts[selectedDistanceUnit]) : false;
  const isHoursRequired = requiredTypes.includes('שע"מ');
  const isDistanceRequired = requiredTypes.includes('ק"מ') || requiredTypes.includes('מייל');

  const canConfirm = isDynamic 
    ? (hasHoursValue || hasDistanceValue)
    : ((!isHoursRequired || hasHoursValue) && (!isDistanceRequired || hasDistanceValue));

  const handleFinalConfirm = () => {
    const finalCounters: CounterValue[] = [];
    if (hasHoursValue) finalCounters.push({ type: 'שע"מ', value: drafts['שע"מ'] });
    if (selectedDistanceUnit && isValidEntry(drafts[selectedDistanceUnit])) {
      finalCounters.push({ type: selectedDistanceUnit, value: drafts[selectedDistanceUnit] });
    }
    onConfirm(finalCounters);
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in slide-in-from-bottom-4 duration-500 overflow-hidden">
      {/* Header - Compact */}
      <div className="flex items-center justify-between mb-4">
        <div>
          <h2 className="text-2xl font-black text-white leading-none">{extinguisher?.name}</h2>
          <p className="text-slate-500 font-bold text-[10px] mt-1 uppercase tracking-widest">הזנת קריאות</p>
        </div>
        <button onClick={onBack} className="p-2 bg-slate-800 rounded-xl text-slate-400 active:scale-90 transition-transform">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      {/* Side-by-Side Selector Grid */}
      <div className="grid grid-cols-2 gap-2 mb-3 shrink-0">
        <button
          onClick={() => setEditingCategory('hours')}
          className={`flex flex-col p-3 rounded-2xl border-2 transition-all text-right h-24 justify-between ${
            editingCategory === 'hours' 
              ? 'bg-orange-500 border-orange-400 text-white shadow-lg' 
              : hasHoursValue 
              ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-500' 
              : 'bg-slate-800 border-slate-700 text-slate-500'
          }`}
        >
          <span className="text-[10px] font-black uppercase tracking-widest leading-none">שע"מ</span>
          <div className="text-2xl font-black tabular-nums">{drafts['שע"מ'] || '---'}</div>
        </button>

        <div 
          onClick={() => setEditingCategory('distance')}
          className={`flex flex-col p-3 rounded-2xl border-2 transition-all text-right h-24 justify-between cursor-pointer ${
            editingCategory === 'distance' 
              ? 'bg-slate-800 border-orange-500 shadow-lg' 
              : hasDistanceValue 
              ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-500' 
              : 'bg-slate-900 border-slate-800 text-slate-600'
          }`}
        >
          <div className="flex items-start justify-between">
            <span className={`text-[10px] font-black uppercase tracking-widest leading-none ${editingCategory === 'distance' ? 'text-orange-400' : ''}`}>מרחק</span>
            <div className="flex bg-slate-950 p-0.5 rounded-md gap-0.5" onClick={e => e.stopPropagation()}>
              {['ק"מ', 'מייל'].map(unit => (
                <button
                  key={unit}
                  onClick={() => {
                    setSelectedDistanceUnit(unit as any);
                    setEditingCategory('distance');
                  }}
                  className={`px-1.5 py-0.5 rounded text-[8px] font-black transition-all ${
                    selectedDistanceUnit === unit ? 'bg-orange-500 text-white' : 'text-slate-600'
                  }`}
                >
                  {unit}
                </button>
              ))}
            </div>
          </div>
          <div className={`text-2xl font-black tabular-nums ${editingCategory === 'distance' ? 'text-white' : ''}`}>
            {selectedDistanceUnit ? (drafts[selectedDistanceUnit] || '---') : '---'}
          </div>
        </div>
      </div>

      {/* Focused Display */}
      <div className="bg-[#1E293B] rounded-2xl border border-slate-700 p-4 mb-3 text-center shrink-0">
        <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">
          מזין: <span className="text-orange-400">{editingCategory === 'hours' ? 'שעות מנוע' : `מרחק (${selectedDistanceUnit})`}</span>
        </div>
        <div className="flex items-center justify-center gap-4">
          <span className={`text-5xl font-black tabular-nums ${currentValue ? 'text-white' : 'text-slate-800'}`}>
            {currentValue || '00000'}
          </span>
          {currentValue && (
            <button onClick={handleClear} className="text-slate-600 hover:text-red-500 p-1">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          )}
        </div>
      </div>

      {/* Numpad - Priority Layout */}
      <div className="flex-1 grid grid-cols-3 gap-2 mb-4">
        {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
          <button 
            key={num} 
            onClick={() => handleKeyPress(num.toString())}
            className="bg-slate-800 rounded-xl text-2xl font-bold text-white active:bg-orange-600 active:text-white border-b-2 border-slate-950 flex items-center justify-center transition-all active:translate-y-0.5 active:border-b-0"
          >
            {num}
          </button>
        ))}
        <button className="invisible" />
        <button 
          onClick={() => handleKeyPress('0')}
          className="bg-slate-800 rounded-xl text-2xl font-bold text-white active:bg-orange-600 border-b-2 border-slate-950 flex items-center justify-center transition-all"
        >
          0
        </button>
        <button 
          onClick={handleDelete}
          className="bg-slate-800 rounded-xl text-red-400 active:bg-red-900 border-b-2 border-slate-950 flex items-center justify-center transition-all"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2M3 12l6.414 6.414a2 2 0 001.414.586H19a2 2 0 002-2V7a2 2 0 00-2-2h-8.172a2 2 0 00-1.414.586L3 12z" />
          </svg>
        </button>
      </div>

      {/* Submit Button - Separated from Numpad */}
      <div className="shrink-0 pb-2">
        <button
          disabled={!canConfirm}
          onClick={handleFinalConfirm}
          className={`w-full py-5 rounded-2xl text-xl font-black transition-all border-b-4 ${
            canConfirm 
              ? 'bg-orange-500 text-white shadow-lg border-orange-700 active:translate-y-1 active:border-b-0' 
              : 'bg-slate-800 text-slate-600 border-slate-900 grayscale opacity-40 cursor-not-allowed'
          }`}
        >
          {canConfirm ? 'סיום ודיווח' : 'הזן נתונים חסרים'}
        </button>
      </div>
    </div>
  );
};

export default DataEntryScreen;

