  const [showSuggestionsFor, setShowSuggestionsFor] = useState<string | null>(null);

  const toggleStatus = (id: string, status: 'ok' | 'anomaly') => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, status, actualSerialNumber: status === 'ok' ? '' : item.actualSerialNumber } : item
    ));
    if (status === 'anomaly') {
      setShowSuggestionsFor(id);
    } else {
      setShowSuggestionsFor(null);
    }
  };

  const updateActualId = (id: string, actualId: string, fromSuggestion = false) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, actualSerialNumber: actualId } : item));
    if (fromSuggestion) {
      setShowSuggestionsFor(null); 
    }
  };

  const allChecked = items.every(i => i.status === 'ok' || (i.status === 'anomaly' && i.actualSerialNumber && i.actualSerialNumber.length > 1));

  return (
    <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500">
