            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-4 overflow-y-auto pr-1">
        {items.map((item) => (
          <div key={item.id} className="bg-slate-800 border-2 border-slate-700 rounded-3xl p-5 flex flex-col gap-4 shadow-xl">
            <div className="flex items-center justify-between w-full">
              <div className="flex-1">
                <div className="text-2xl font-black text-white">{item.name}</div>
                <div className="text-slate-400 font-bold uppercase text-xs tracking-widest flex flex-wrap gap-2 mt-1">
