                  )}
                </div>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => toggleStatus(item.id, 'anomaly')}
                  className={`w-16 h-16 rounded-2xl flex items-center justify-center border-2 transition-all ${
                    item.status === 'anomaly' ? 'bg-red-600 border-red-400 scale-105 shadow-lg shadow-red-900/40' : 'bg-slate-900 border-slate-700 active:bg-slate-800'
                  }`}
                >
                  <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>

                <button 
                  onClick={() => toggleStatus(item.id, 'ok')}
                  className={`w-16 h-16 rounded-2xl flex items-center justify-center border-2 transition-all ${
                    item.status === 'ok' ? 'bg-emerald-600 border-emerald-400 scale-105 shadow-lg shadow-emerald-900/40' : 'bg-slate-900 border-slate-700 active:bg-slate-800'
                  }`}
                >
                  <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
                  </svg>
                </button>
              </div>
            </div>

            {item.status === 'anomaly' && (
              <div className="animate-in slide-in-from-top-2 duration-300">
                <label className="block text-slate-400 text-sm font-bold mb-2 mr-1">הזן מס"ד שנמצא בפועל (בדיקה מול מלאי):</label>
                <div className="relative">
                  <input 
                    type="text"
                    placeholder="הקלד מספר מס״ד לחיפוש..."
                    value={item.actualSerialNumber || ''}
                    onFocus={() => setShowSuggestionsFor(item.id)}
                    onChange={(e) => {
                      updateActualId(item.id, e.target.value);
                      setShowSuggestionsFor(item.id);
                    }}
                    className="w-full bg-slate-900 border-2 border-slate-600 rounded-2xl p-4 text-xl font-bold text-white outline-none focus:border-red-500 transition-all placeholder:text-slate-700"
                  />

