          {showSuggestions && filteredSuggestions.length > 0 && (
            <div className="absolute bottom-full left-0 right-0 mb-3 bg-slate-900 border-2 border-slate-700 rounded-2xl overflow-hidden shadow-2xl z-50 animate-in fade-in slide-in-from-bottom-2 max-h-48 overflow-y-auto">
