              <div className="bg-slate-800 px-4 py-2 text-[10px] font-black text-slate-500 uppercase tracking-widest border-b border-slate-700">כלים מוכרים במערכת</div>
              {filteredSuggestions.map((v) => (
                <button
                  key={v}
                  onMouseDown={() => handleSelect(v)}
                  className="w-full p-5 text-center hover:bg-orange-500/10 hover:text-orange-400 text-white text-2xl font-black border-b border-slate-800 last:border-0 transition-colors"
                >
                  {v}
                </button>
              ))}
            </div>
          )}
        </div>

        <button 
          disabled={!isButtonEnabled}
          onClick={() => onNext(nextId)}
          className={`w-full py-8 rounded-3xl text-3xl font-black shadow-xl transition-all border-b-4 ${
            isButtonEnabled 
              ? 'bg-orange-500 text-white border-orange-700 active:translate-y-1 active:border-b-0 shadow-orange-500/20' 
              : 'bg-slate-800 text-slate-600 border-slate-900 opacity-50 cursor-not-allowed grayscale'
          }`}
        >
          אמת כלי חדש
        </button>

        <button 
          onClick={onFinishBatch}
          className="w-full py-6 bg-slate-900/50 text-slate-500 rounded-3xl text-xl font-bold active:bg-slate-800 transition-all border-2 border-slate-800 border-dashed"
        >
          סיום סבב אימותים
        </button>
      </div>

      <div className="mt-8 text-center">
        <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">SAP S/4HANA • Field Service Mode</p>
      </div>
    </div>
  );
