interface AuditSummaryScreenProps {
  items: Extinguisher[];
  onConfirm: (counters: CounterValue[]) => void;
  onBack: () => void;
}

const AuditSummaryScreen: React.FC<AuditSummaryScreenProps> = ({ items, onConfirm, onBack }) => {
  const [drafts, setDrafts] = useState<Record<CounterType, string>>({
    'שע"מ': '',
    'ק"מ': '',
    'מייל': ''
  });

  const [editingCategory, setEditingCategory] = useState<'hours' | 'distance'>('hours');
  const [selectedDistanceUnit, setSelectedDistanceUnit] = useState<'ק"מ' | 'מייל'>('ק"מ');

  const activeType: CounterType = editingCategory === 'hours' ? 'שע"מ' : selectedDistanceUnit;
  const currentValue = drafts[activeType];
  const anomalies = items.filter(i => i.status === 'anomaly').length;

  const handleKeyPress = (num: string) => {
    setDrafts(prev => {
      const current = prev[activeType];
      if (current.length < 8) return { ...prev, [activeType]: current + num };
      return prev;
    });
  };

  const handleDelete = () => {
    setDrafts(prev => ({ ...prev, [activeType]: prev[activeType].slice(0, -1) }));
  };

  const handleClear = () => {
    setDrafts(prev => ({ ...prev, [activeType]: '' }));
  };

  const isValid = drafts['שע"מ'].length >= 2 && drafts[selectedDistanceUnit].length >= 2;

  const handleFinalConfirm = () => {
    const finalCounters: CounterValue[] = [
      { type: 'שע"מ', value: drafts['שע"מ'] },
      { type: selectedDistanceUnit, value: drafts[selectedDistanceUnit] }
    ];
    onConfirm(finalCounters);
  };

  return (
    <div className="h-full flex flex-col animate-in fade-in zoom-in-95 duration-500 overflow-hidden">
      {/* Header */}
      <div className="mb-4 shrink-0">
        <h2 className="text-4xl font-black text-white leading-tight">סיכום אימות</h2>
