            {anomalies} החלפות נמצאו
          </span>
        </div>
      </div>

      {/* Dual Selector Grid */}
      <div className="grid grid-cols-2 gap-3 mb-4 shrink-0">
        <button
          onClick={() => setEditingCategory('hours')}
