          <div className="text-2xl font-black tabular-nums tracking-tighter">{drafts['שע"מ'] || '---'}</div>
        </button>

        <button 
          onClick={() => setEditingCategory('distance')}
          className={`flex flex-col p-4 rounded-3xl border-2 transition-all text-right h-24 justify-between ${
            editingCategory === 'distance' 
              ? 'bg-slate-800 border-orange-500 shadow-xl' 
              : drafts[selectedDistanceUnit].length > 0
              ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-500' 
              : 'bg-slate-900 border-slate-800 text-slate-600'
          }`}
        >
          <div className="flex items-start justify-between w-full">
            <span className={`text-[9px] font-black uppercase tracking-widest leading-none ${editingCategory === 'distance' ? 'text-orange-400' : ''}`}>מרחק נסיעה</span>
            <div className="flex bg-slate-950 p-0.5 rounded-lg gap-0.5" onClick={e => e.stopPropagation()}>
              {['ק"מ', 'מייל'].map(unit => (
                <button
                  key={unit}
                  onClick={() => {
                    setSelectedDistanceUnit(unit as any);
                    setEditingCategory('distance');
                  }}
                  className={`px-1.5 py-0.5 rounded text-[7px] font-black transition-all ${
                    selectedDistanceUnit === unit ? 'bg-orange-500 text-white' : 'text-slate-600'
                  }`}
                >
                  {unit}
                </button>
              ))}
            </div>
          </div>
          <div className={`text-2xl font-black tabular-nums tracking-tighter ${editingCategory === 'distance' ? 'text-white' : ''}`}>
            {drafts[selectedDistanceUnit] || '---'}
          </div>
        </button>
      </div>

      {/* Main Value Display */}
      <div className="bg-[#1E293B] rounded-3xl border-2 border-slate-700 p-4 mb-4 text-center shrink-0 shadow-inner">
        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">
          {editingCategory === 'hours' ? 'מונה שע"מ' : `מונה מרחק (${selectedDistanceUnit})`}
        </div>
        <div className="flex items-center justify-center gap-4 h-12">
          <span className={`text-5xl font-black tabular-nums ${currentValue ? 'text-white' : 'text-slate-800'}`}>
            {currentValue || '00000'}
          </span>
          {currentValue && (
            <button onClick={handleClear} className="text-slate-600 hover:text-red-500 p-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          )}
        </div>
      </div>

      {/* Numpad Area */}
      <div className="flex-1 grid grid-cols-3 gap-2 min-h-0 mb-4">
        {[1, 2, 3, 4, 5, 6, 7, 8, 9, '.', 0].map(num => (
          <button 
            key={num.toString()} 
            onClick={() => handleKeyPress(num.toString())}
            className="bg-slate-800 rounded-2xl text-2xl font-bold text-white active:bg-orange-600 border-b-4 border-slate-950 flex items-center justify-center transition-all active:translate-y-1 active:border-b-0"
          >
            {num}
          </button>
        ))}
        <button 
          onClick={handleDelete}
          className="bg-slate-800 rounded-2xl text-red-400 active:bg-red-900 border-b-4 border-slate-950 flex items-center justify-center transition-all active:translate-y-1 active:border-b-0"
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2M3 12l6.414 6.414a2 2 0 001.414.586H19a2 2 0 002-2V7a2 2 0 00-2-2h-8.172a2 2 0 00-1.414.586L3 12z" />
          </svg>
        </button>
      </div>

      <div className="flex gap-3 shrink-0 pb-2">
        <button onClick={onBack} className="flex-1 py-5 bg-slate-800 text-slate-300 rounded-3xl text-xl font-black border-b-4 border-slate-900 active:border-b-0 active:translate-y-1">חזור</button>
        <button
          disabled={!isValid}
          onClick={handleFinalConfirm}
          className={`flex-[2] py-5 rounded-3xl text-xl font-black border-b-4 transition-all ${
            isValid ? 'bg-orange-500 text-white shadow-lg border-orange-700 active:border-b-0 active:translate-y-1' : 'bg-slate-800 text-slate-600 grayscale'
          }`}
        >
          אישור וסיום כלי
        </button>
      </div>
    </div>
  );
};

export default AuditSummaryScreen;

// Fix: Removed broken 'armament' declaration and redundant FlowStep enum.
export enum FlowStep {
  TRIGGER = 'TRIGGER',
  IDENTIFY = 'IDENTIFY',
  DATA_ENTRY = 'DATA_ENTRY',
  SUCCESS = 'SUCCESS',
  AUDIT_CHECK = 'AUDIT_CHECK',
  AUDIT_SUMMARY = 'AUDIT_SUMMARY',
  NEXT_VEHICLE = 'NEXT_VE_INPUT',
  BATCH_SUMMARY = 'BATCH_SUMMARY'
}

export enum ActionType {
  DISASSEMBLE = 'DISASSEMBLE',
  ASSEMBLE = 'ASSEMBLE',
  AUDIT = 'AUDIT'
}

export type CounterType = 'שע"מ' | 'ק"מ' | 'מייל';

export interface CounterValue {
  type: CounterType;
  value: string;
}

export type LocationStatus = 'current_vehicle' | 'other_vehicle' | 'unit_stock' | 'in_air';

export interface Extinguisher {
  id: string;
  name: string;
  serialNumber: string;
  materialNumber?: string;
  status?: 'ok' | 'anomaly' | null;
  actualSerialNumber?: string;
  actualMaterialNumber?: string;
  counters?: CounterValue[]; 
  requiredCounters?: CounterType[]; 
  isNew?: boolean;
  locationStatus?: LocationStatus;
  locationName?: string;
}

export interface AnomalyDetail {
  vehicleId: string;
  oldSerial: string;
  newSerial: string;
  newMaterial?: string;
  itemName: string;
}

export interface BatchStats {
  vehiclesCount: number;
  extinguishersChecked: number;
  anomaliesFound: number;
  vehiclesList: string[];
  anomaliesList: AnomalyDetail[];
}

import React, { useState } from 'react';
import { FlowStep, ActionType, Extinguisher, BatchStats, CounterValue, AnomalyDetail } from './types';
import TriggerScreen from './components/TriggerScreen';
import IdentifyScreen from './components/IdentifyScreen';
import DataEntryScreen from './components/DataEntryScreen';
import SuccessScreen from './components/SuccessScreen';
import AuditScreen from './components/AuditScreen';
import AuditSummaryScreen from './components/AuditSummaryScreen';
import NextVehicleScreen from './components/NextVehicleScreen';
import BatchSummaryScreen from './components/BatchSummaryScreen';

// Each vehicle now has exactly one extinguisher as per user requirement
const VEHICLE_EXTINGUISHERS: Extinguisher[] = [
  { id: '1', name: 'מטף ראשי', serialNumber: '12345', materialNumber: 'M-100', status: null, counters: [], requiredCounters: ['שע"מ', 'ק"מ'] },
];

// Inventory list for assembly flow (multiple items)
const INVENTORY_EXTINGUISHERS: Extinguisher[] = [
  { id: '101', name: 'מטף אבקה 6 ק"ג', serialNumber: 'S-9901', materialNumber: 'MAT-662', counters: [], requiredCounters: [] },
  { id: '102', name: 'מטף אבקה 6 ק"ג', serialNumber: 'S-9902', materialNumber: 'MAT-662', counters: [], requiredCounters: [] },
  { id: '103', name: 'מטף הלון 2.5 ק"ג', serialNumber: 'H-4410', materialNumber: 'MAT-884', counters: [], requiredCounters: [] },
  { id: '104', name: 'מטף הלון 2.5 ק"ג', serialNumber: 'H-4411', materialNumber: 'MAT-884', counters: [], requiredCounters: [] },
];

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState<FlowStep>(FlowStep.TRIGGER);
  const [action, setAction] = useState<ActionType | null>(null);
  const [selectedExtinguisher, setSelectedExtinguisher] = useState<Extinguisher | null>(null);
  const [currentVehicleId, setCurrentVehicleId] = useState('123456');

  const [auditList, setAuditList] = useState<Extinguisher[]>(VEHICLE_EXTINGUISHERS);
  const [batchStats, setBatchStats] = useState<BatchStats>({
    vehiclesCount: 0,
    extinguishersChecked: 0,
    anomaliesFound: 0,
    vehiclesList: [],
    anomaliesList: []
  });

  const handleActionSelect = (type: ActionType) => {
    setAction(type);
    if (type === ActionType.AUDIT) {
      setAuditList(VEHICLE_EXTINGUISHERS.map(e => ({ ...e, status: null, actualSerialNumber: '', actualMaterialNumber: '' })));
      setCurrentStep(FlowStep.AUDIT_CHECK);
    } else {
      setCurrentStep(FlowStep.IDENTIFY);
    }
  };

  const handleExtinguisherSelect = (ext: Extinguisher) => {
    setSelectedExtinguisher(ext);
    setCurrentStep(FlowStep.DATA_ENTRY);
  };

  const handleAuditFinish = () => {
    setCurrentStep(FlowStep.AUDIT_SUMMARY);
  };

  const handleAuditFinalSubmit = (counters: CounterValue[]) => {
    const anomalies = auditList.filter(e => e.status === 'anomaly');
    const newAnomalyDetails: AnomalyDetail[] = anomalies.map(e => ({
      vehicleId: currentVehicleId,
      oldSerial: e.serialNumber,
      newSerial: e.actualSerialNumber || '---',
      newMaterial: e.actualMaterialNumber,
      itemName: e.name
    }));

    setBatchStats(prev => ({
      vehiclesCount: prev.vehiclesCount + 1,
      extinguishersChecked: prev.extinguishersChecked + auditList.length,
      anomaliesFound: prev.anomaliesFound + anomalies.length,
      vehiclesList: [...prev.vehiclesList, currentVehicleId],
      anomaliesList: [...prev.anomaliesList, ...newAnomalyDetails]
    }));
    // Fix: Using FlowStep.NEXT_VEHICLE as defined in types.ts instead of FlowStep.NEXT_VE_INPUT
    setCurrentStep(FlowStep.NEXT_VEHICLE); 
  };

  const handleNewVehicle = (newId: string) => {
    setCurrentVehicleId(newId);
    setAuditList(VEHICLE_EXTINGUISHERS.map(e => ({ ...e, status: null, actualSerialNumber: '', actualMaterialNumber: '' })));
    setCurrentStep(FlowStep.AUDIT_CHECK);
  };

  const handleReset = () => {
    setAction(null);
    setSelectedExtinguisher(null);
    setBatchStats({
      vehiclesCount: 0,
      extinguishersChecked: 0,
      anomaliesFound: 0,
      vehiclesList: [],
      anomaliesList: []
    });
    setCurrentStep(FlowStep.TRIGGER);
  };

  const renderStep = () => {
    switch (currentStep) {
      case FlowStep.TRIGGER:
        return <TriggerScreen onSelect={handleActionSelect} />;
      case FlowStep.IDENTIFY:
        return (
          <IdentifyScreen 
            extinguishers={action === ActionType.ASSEMBLE ? INVENTORY_EXTINGUISHERS : VEHICLE_EXTINGUISHERS} 
            onSelect={handleExtinguisherSelect}
            onBack={handleReset}
            actionType={action}
          />
        );
      case FlowStep.DATA_ENTRY:
        return (
          <DataEntryScreen 
            onConfirm={(counters: CounterValue[]) => {
              if (selectedExtinguisher) {
                setSelectedExtinguisher({ ...selectedExtinguisher, counters });
              }
              setCurrentStep(FlowStep.SUCCESS);
            }}
            onBack={() => setCurrentStep(FlowStep.IDENTIFY)}
            extinguisher={selectedExtinguisher}
          />
        );
      case FlowStep.AUDIT_CHECK:
        return (
          <AuditScreen 
            items={auditList} 
            setItems={setAuditList} 
            onFinish={handleAuditFinish} 
            onBack={handleReset}
            vehicleId={currentVehicleId}
          />
        );
      case FlowStep.AUDIT_SUMMARY:
        return (
          <AuditSummaryScreen 
            items={auditList} 
            onConfirm={handleAuditFinalSubmit}
            onBack={() => setCurrentStep(FlowStep.AUDIT_CHECK)}
          />
        );
      // Fix: Updated from FlowStep.NEXT_VE_INPUT to FlowStep.NEXT_VEHICLE
      case FlowStep.NEXT_VEHICLE:
        return (
          <NextVehicleScreen 
            onNext={handleNewVehicle} 
            onFinishBatch={() => setCurrentStep(FlowStep.BATCH_SUMMARY)} 
          />
        );
      case FlowStep.BATCH_SUMMARY:
        return <BatchSummaryScreen stats={batchStats} onFinish={handleReset} />;
      case FlowStep.SUCCESS:
        return (
          <SuccessScreen 
            extinguisher={selectedExtinguisher}
            onFinish={handleReset} 
          />
        );
      default:
        return <TriggerScreen onSelect={handleActionSelect} />;
    }
  };

  return (
    <div className="h-screen w-full flex flex-col bg-[#0F172A] text-slate-100 overflow-hidden font-['Assistant']">
      <header className="px-6 py-4 flex justify-between items-center border-b border-slate-800 bg-[#1E293B] shrink-0">
        <div className="flex flex-col">
          <h1 className="text-xs uppercase tracking-widest text-slate-400 font-bold">ניהול אמצעי כיבוי</h1>
          <p className="text-lg font-extrabold text-white">כלי: {currentVehicleId}</p>
        </div>
        <div className="flex items-center gap-3">
           <div className="hidden md:block text-left">
              <p className="text-xs text-slate-400 font-bold">טכנאי מורשה</p>
              <p className="text-sm font-bold">אלכס ב.</p>
           </div>
           <div className="w-10 h-10 rounded-full bg-orange-500/20 border border-orange-500 flex items-center justify-center">
             <span className="text-sm font-extrabold text-orange-500">א"ב</span>
           </div>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto relative p-6">
        {renderStep()}
      </main>

      <div className="px-6 pb-6 flex gap-2 shrink-0">
        {[FlowStep.TRIGGER, FlowStep.IDENTIFY, FlowStep.DATA_ENTRY, FlowStep.SUCCESS].map((step, idx) => {
          // Fix: Updated from FlowStep.NEXT_VE_INPUT to FlowStep.NEXT_VEHICLE
          const isActive = currentStep === step || 
            (currentStep.startsWith('AUDIT') && idx === 1) || 
            (currentStep === FlowStep.NEXT_VEHICLE && idx === 2);
          return (
            <div 
              key={step} 
              className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
                isActive ? 'bg-orange-500 shadow-[0_0_8px_rgba(249,115,22,0.5)]' : 'bg-slate-800'
              }`} 
            />
          );
        })}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Extinguisher, LocationStatus } from '../types';

interface AuditScreenProps {
  items: Extinguisher[];
  setItems: React.Dispatch<React.SetStateAction<Extinguisher[]>>;
  onFinish: () => void;
  onBack: () => void;
  vehicleId: string;
}

// Global pool with location metadata for auditing
const GLOBAL_EXTINGUISHERS_POOL: Partial<Extinguisher>[] = [
  { serialNumber: 'S-1001', materialNumber: 'MAT-101', name: 'מטף אבקה 6 ק"ג', locationStatus: 'unit_stock' },
  { serialNumber: 'S-1002', materialNumber: 'MAT-101', name: 'מטף אבקה 6 ק"ג', locationStatus: 'other_vehicle', locationName: 'כלי 776-554' },
  { serialNumber: 'S-2001', materialNumber: 'MAT-202', name: 'מטף הלון 2.5 ק"ג', locationStatus: 'current_vehicle' },
  { serialNumber: 'S-2002', materialNumber: 'MAT-202', name: 'מטף הלון 2.5 ק"ג', locationStatus: 'in_air' },
  { serialNumber: 'S-9999', materialNumber: 'MAT-909', name: 'מטף קצף 9 ליטר', locationStatus: 'unit_stock' },
  { serialNumber: 'S-12345', materialNumber: 'MAT-505', name: 'מטף פחמן דו-חמצני', locationStatus: 'other_vehicle', locationName: 'כלי 112-233' },
  { serialNumber: '12345', materialNumber: 'M-100', name: 'מטף ראשי' }
];

const StatusBadge: React.FC<{ status?: LocationStatus; name?: string }> = ({ status, name }) => {
  switch (status) {
