      return null;
  }
};

const AuditScreen: React.FC<AuditScreenProps> = ({ items, setItems, onFinish, onBack, vehicleId }) => {
  const [showSuggestionsFor, setShowSuggestionsFor] = useState<string | null>(null);

  const toggleStatus = (id: string, status: 'ok' | 'anomaly') => {
    setItems(prev => prev.map(item => 
      item.id === id ? { ...item, status, actualSerialNumber: status === 'ok' ? '' : item.actualSerialNumber, actualMaterialNumber: '' } : item
    ));
    if (status === 'anomaly') {
      setShowSuggestionsFor(id);
    } else {
      setShowSuggestionsFor(null);
    }
  };

  const updateActualId = (id: string, actualId: string, fromSuggestion = false, suggestionMaterial?: string) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        return { 
          ...item, 
          actualSerialNumber: actualId, 
          actualMaterialNumber: fromSuggestion ? (suggestionMaterial || '') : item.actualMaterialNumber 
        };
      }
      return item;
    }));
    if (fromSuggestion) {
      setShowSuggestionsFor(null); 
    }
  };

  const updateActualMaterial = (id: string, material: string) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, actualMaterialNumber: material } : item));
  };

  const isNewItem = (serial?: string) => {
    if (!serial) return false;
    return !GLOBAL_EXTINGUISHERS_POOL.some(p => p.serialNumber === serial);
  };

  const allChecked = items.every(i => {
    if (i.status === null) return false;
    if (i.status === 'anomaly' && i.actualSerialNumber && i.actualSerialNumber.length > 0) {
      // If serial is provided but not in pool, material number is mandatory
      if (isNewItem(i.actualSerialNumber)) {
        return i.actualMaterialNumber && i.actualMaterialNumber.length > 1;
      }
    }
    return true;
  });

  return (
    <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500 overflow-hidden">
      <div className="mb-6 flex items-start justify-between shrink-0">
        <div>
          <h2 className="text-4xl font-black text-white leading-tight">אימות מטפים</h2>
          <p className="text-slate-400 text-lg mt-1 font-bold italic">כלי: {vehicleId}</p>
        </div>
        <button onClick={onBack} className="p-4 bg-slate-800 rounded-2xl active:bg-slate-700 transition-colors shadow-lg">
          <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      <div className="flex-1 space-y-4 overflow-y-auto pr-1 min-h-0">
        {items.map((item) => (
          <div key={item.id} className="bg-slate-800 border-2 border-slate-700 rounded-3xl p-5 flex flex-col gap-4 shadow-xl">
            <div className="flex items-center justify-between w-full">
              <div className="flex-1">
                <div className="text-2xl font-black text-white">{item.name}</div>
                <div className="text-slate-400 font-bold uppercase text-[10px] tracking-widest flex flex-wrap gap-2 mt-1">
                  <span className="bg-slate-900 px-2 py-0.5 rounded">מס"ד: {item.serialNumber}</span>
                  {item.materialNumber && (
                    <span className="bg-orange-500/10 text-orange-400 px-2 py-0.5 rounded border border-orange-500/20 tracking-tighter">מק"ט: {item.materialNumber}</span>
                  )}
                </div>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => toggleStatus(item.id, 'anomaly')}
                  className={`w-16 h-16 rounded-2xl flex items-center justify-center border-2 transition-all ${
                    item.status === 'anomaly' ? 'bg-red-600 border-red-400 scale-105 shadow-lg shadow-red-900/40' : 'bg-slate-900 border-slate-700 active:bg-slate-800'
                  }`}
                >
                  <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>

                <button 
                  onClick={() => toggleStatus(item.id, 'ok')}
                  className={`w-16 h-16 rounded-2xl flex items-center justify-center border-2 transition-all ${
                    item.status === 'ok' ? 'bg-emerald-600 border-emerald-400 scale-105 shadow-lg shadow-emerald-900/40' : 'bg-slate-900 border-slate-700 active:bg-slate-800'
                  }`}
                >
                  <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
                  </svg>
                </button>
              </div>
            </div>

            {item.status === 'anomaly' && (
              <div className="animate-in slide-in-from-top-2 duration-300 space-y-4">
                <div>
                  <label className="block text-slate-400 text-xs font-bold mb-2 mr-1 uppercase tracking-tighter">
                    הזן מס"ד שנמצא בפועל:
                  </label>
                  <div className="relative">
                    <input 
                      type="text"
                      placeholder="הקלד מספר מס״ד לחיפוש..."
                      value={item.actualSerialNumber || ''}
                      onFocus={() => setShowSuggestionsFor(item.id)}
                      onChange={(e) => {
                        updateActualId(item.id, e.target.value);
                        setShowSuggestionsFor(item.id);
                      }}
                      className="w-full bg-slate-900 border-2 border-slate-600 rounded-2xl p-4 text-xl font-bold text-white outline-none focus:border-red-500 transition-all placeholder:text-slate-800"
                    />

                    {showSuggestionsFor === item.id && item.actualSerialNumber && item.actualSerialNumber.length > 0 && (
                      <div className="absolute top-full left-0 right-0 mt-2 bg-slate-900 border-2 border-slate-700 rounded-2xl overflow-hidden shadow-2xl z-20 max-h-56 overflow-y-auto animate-in fade-in slide-in-from-top-2">
                        <div className="bg-slate-800 px-4 py-2 text-[9px] font-black text-slate-500 uppercase tracking-widest border-b border-slate-700 flex justify-between">
                          <span>הצעות ממלאי ארגוני</span>
                          <span>SAP S/4HANA</span>
                        </div>
                        {GLOBAL_EXTINGUISHERS_POOL
                          .filter(s => s.serialNumber?.toLowerCase().includes(item.actualSerialNumber!.toLowerCase()))
                          .map(suggestion => (
                            <button
                              key={suggestion.serialNumber}
                              onClick={() => updateActualId(item.id, suggestion.serialNumber!, true, suggestion.materialNumber)}
                              className="w-full p-4 text-right hover:bg-slate-800 text-slate-200 font-bold border-b border-slate-800 last:border-0 transition-colors flex justify-between items-center group"
                            >
                              <div className="flex-1">
                                 <div className="flex items-center gap-2 mb-0.5">
